CREATE procedure [dbo].[ROI_Conversion_RequestMain]
	@requestId bigint,
    @ConversionSource varchar(50),
    @isWheaton varchar(20),
    @defaultFacilityCode varchar(10),
    @defaultFacilityName varchar(25),
    @defaultInvoiceDueDays int
as
BEGIN
BEGIN TRY
SET NOCOUNT ON
if exists(select 1 from cabinet.dbo.ROI_RequestMain where ROI_RequestMain_Seq=@requestId)
begin
exec ROI_Conversion_Delete_RequestCore @requestId
end
####ROI_Conversion_RequestMain_SP_declares####
####ROI_Conversion_RequestMain_SP_RequestMainXMLConversion####
####ROI_Conversion_RequestMain_SP_DraftInvoiceXMLConversion####
if not(@requestor_type_name = 'Migration' and @request_reason = 'Migration')
BEGIN
	if(@isWheaton <> 'true')
	BEGIN
		####ROI_Conversion_RequestMain_SP_NonWheatonInvoiceXMLConversion####
		####ROI_Conversion_RequestMain_SP_NonWheatonPrebillXMLConversion####
	END
	ELSE
	BEGIN
		####ROI_Conversion_RequestMain_SP_WheatonInvoiceXMLConversion####
		####ROI_Conversion_RequestMain_SP_WheatonPrebillXMLConversion####
	END
		####ROI_Conversion_RequestMain_SP_UnbillableConversion####
END
####ROI_Conversion_RequestMain_SP_ReleaseXMLConversion####
END TRY
BEGIN CATCH
	DECLARE @ErrMsg nvarchar(4000), @ErrSeverity int, @ErrLine int;
	SELECT
	@ErrSeverity = ERROR_SEVERITY(),
	@ErrLine = ERROR_LINE(),
	@ErrMsg = ERROR_MESSAGE();
	RAISERROR('Error Message: %s; Error Line: %d', @ErrSeverity, 1, @ErrMsg, @ErrLine)
END CATCH
END

		
