end else begin select top 1 @tempTypeID=ROI_RequestorType_Seq from [cabinet].[dbo].[ROI_RequestorType] where name=@requestor_type_name end
if not exists (select 1 from [cabinet].[dbo].[ROI_Requestor] where NameFirst=@nFirst and NameLast=@nLast and ROI_RequestorType_Seq=@tempTypeID) begin insert into [cabinet].[dbo].[ROI_Requestor](Created_Dt,Created_By_Seq,Modified_Dt,Modified_By_Seq,Record_Version,ROI_RequestorType_Seq,AccountNumber,Active,Frequent,PrePayRequired,CertLetterRequired,IsPatient, Title,NameFirst,NameMiddle,NameLast,Suffix) values(@Created_Dt,@Created_By_Seq,@Modified_Dt,@Modified_By_Seq,@Record_Version,@tempTypeID,NULL,1,1,0,0,0,NULL,@nFirst,NULL, @nLast,NULL) SELECT @tempID=SCOPE_IDENTITY() end else begin select top 1 @tempID=ROI_Requestor_Seq from [cabinet].[dbo].[ROI_Requestor] where NameFirst=@nFirst and NameLast=@nLast and ROI_RequestorType_Seq=@tempTypeID end
insert into [cabinet].[dbo].[ROI_RequestCoreRequestor] ( ROI_RequestCore_Seq, ROI_Requestor_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, RequestorTypeName, WorkPhone, HomePhone, CellPhone, ContactName, ContactPhone, Fax, NameFirst, nameLast, RequestorType) select @requestId, @tempID, @Created_Dt, @Created_By_Seq, @Modified_Dt, @Modified_By_Seq ,@Record_Version, RequestorTypeName, WorkPhone, HomePhone, CellPhone, ContactName, ContactPhone, Fax, NameFirst, nameLast, RequestorType from @tmpRequestCoreRequestor; set @requestor_seq=@tempID; END else BEGIN DECLARE @ErrorMessage NVARCHAR(4000); DECLARE @ErrorSeverity INT; DECLARE @ErrorState INT;
SELECT @ErrorMessage = ERROR_MESSAGE(), @ErrorSeverity = ERROR_SEVERITY(), @ErrorState = ERROR_STATE(); RAISERROR (@ErrorMessage, @ErrorSeverity,@ErrorState); END END CATCH
insert into @tmpROIPatient SELECT NULLIF(t.c.value('@mrn','varchar(20)'), '') as [MRN], NULLIF(t.c.value('@facility','varchar(10)'), '') as [FACILITY], NULLIF(t.c.value('name[1]','varchar(40)'), '') as [NAME], NULLIF(t.c.value('ssn[1]','varchar(27)'), '') as [SSN], [SEX] = case t.c.value('gender[1]','varchar(10)') when 'Male' then 'M' when 'Female' then 'F' else NULL end, NULLIF(t.c.value('dob[1]','datetime'), '') as [DOB], NULLIF(t.c.value('epn[1]','varchar(50)'), '') as [EPN], [VIP] = case t.c.value('is-vip[1]','varchar(10)') when 'true' then 1 when 'false' then 0 else 0 end, [PATIENTLOCKED] = case t.c.value('patientLocked[1]','varchar(10)') when 'true' then 1 when 'false' then 0 else 0 end FROM @request.nodes('/request/item[@source="hpf"]/patient') as t(c);
insert into @tmpROIEncounter SELECT NULLIF(t.c.value('@mrn','varchar(20)'), '') as [MRN], NULLIF(t.c.value('@facility','varchar(10)'), '') as [FACILITY], NULLIF(t2.c2.value('@id','varchar(20)'), '') as [ENCOUNTER], NULLIF(t2.c2.value('admitDate[1]','smalldatetime'), '') as [ADMITTED], NULLIF(t2.c2.value('discharge-date[1]','smalldatetime'), '') as [DISCHARGED], NULLIF(t2.c2.value('patientType[1]','varchar(10)'), '') as [PT_TYPE], NULLIF(t2.c2.value('patientService[1]','varchar(10)'), '') as [SERVICE], [VIP] = case t2.c2.value('is-vip[1]','varchar(10)') when 'true' then 1 when 'false' then 0 else 0 end, [LOCKOUT] = case t2.c2.value('is-locked[1]','varchar(10)') when 'true' then 1 when 'false' then 0 else 0 end, [HAS_DEFICIENCY] = case t2.c2.value('hasDeficiency[1]','varchar(10)') when 'true' then 1 when 'false' then 0 else 0 end FROM @request.nodes('/request/item[@source="hpf"]/patient') as t(c) cross apply t.c.nodes('encounter') as t2(c2);
insert into @tmpROIDocument SELECT NULLIF(t.c.value('@mrn','varchar(20)'), '') as [MRN], NULLIF(t.c.value('@facility','varchar(10)'), '') as [FACILITY], null as [ENCOUNTER], NULLIF(t1.c1.value('@type','varchar(30)'), '') as [DOC_NAME], NULLIF(t1.c1.value('subtitle[1]','varchar(30)'), '') as [SUBTITLE], NULLIF(t1.c1.value('chart-order[1]','varchar(10)'), '') as [CHART_ORDER], NULLIF(t1.c1.value('doc-id[1]','varchar(max)'), '') as [DOC_TYPE_ID], NULLIF(t1.c1.value('(doc-id/@value)[1]','varchar(max)'), '') as [DOC_ID], NULLIF(t0.c0.value('@imnet-id[1]','varchar(50)'), '') as [IMNET] FROM @request.nodes('/request/item[@source="hpf"]/patient') as t(c) cross apply t.c.nodes('global-document') as t1(c1) cross apply t1.c1.nodes('version/page[1]') as t0(c0) Union SELECT NULLIF(t2.c2.value('@mrn','varchar(20)'), '') as [MRN], NULLIF(t2.c2.value('@facility','varchar(10)'), '') as [FACILITY], NULLIF(t3.c3.value('@id','varchar(20)'), '') as [ENCOUNTER], NULLIF(t4.c4.value('@type','varchar(30)'), '') as [DOC_NAME], NULLIF(t4.c4.value('subtitle[1]','varchar(30)'), '') as [SUBTITLE], NULLIF(t4.c4.value('chart-order[1]','varchar(10)'), '') as [CHART_ORDER], NULLIF(t4.c4.value('doc-id[1]','varchar(max)'), '') as [DOC_TYPE_ID], NULLIF(t4.c4.value('(doc-id/@value)[1]','varchar(max)'), '') as [DOC_ID], NULLIF(t5.c5.value('@imnet-id[1]','varchar(50)'), '1') as [IMNET] FROM @request.nodes('/request/item[@source="hpf"]/patient') as t2(c2) cross apply t2.c2.nodes('encounter') as t3(c3) cross apply t3.c3.nodes('document') as t4(c4) cross apply t4.c4.nodes('version/page[1]') as t5(c5);
UPDATE a SET a.doc_id = d.doc_id FROM @tmpROIDocument a JOIN cabinet.dbo.documents d on ( a.facility = d.facility AND a.encounter = d.encounter AND a.doc_name = d.doc_name AND coalesce(a.subtitle, '') = coalesce(d.subtitle, '')) JOIN cabinet.dbo.pages p on (a.IMNET = p.imnet) JOIN versions v on p.version_id = v.version_id WHERE a.doc_id IS NULL
UPDATE a SET a.doc_id = d.doc_id FROM @tmpROIDocument a JOIN cabinet.dbo.documents d on ( a.facility = d.facility AND a.mrn = d.mrn AND a.doc_name = d.doc_name AND coalesce(a.subtitle, '') = coalesce(d.subtitle, '')) JOIN cabinet.dbo.pages p on (a.IMNET = p.imnet) JOIN versions v on p.version_id = v.version_id WHERE a.doc_id IS NULL
insert into @tmpROIVersion SELECT NULLIF(t.c.value('@mrn','varchar(20)'), '') as [MRN], NULLIF(t.c.value('@facility','varchar(10)'), '') as [FACILITY], null as [ENCOUNTER], NULLIF(t1.c1.value('@type','varchar(30)'), '') as [DOC_NAME], NULLIF(t1.c1.value('subtitle[1]','varchar(30)'), '') as [SUBTITLE], NULLIF(t1.c1.value('(doc-id/@value)[1]','varchar(max)'), '') as [DOC_ID], NULLIF(t7.c7.value('@imnet-id[1]','varchar(50)'), '') as [IMNET], NULLIF(t6.c6.value('@number','varchar(max)'), '') as [VersionNumber] from @request.nodes('/request/item[@source="hpf"]/patient') as t(c) cross apply t.c.nodes('global-document') as t1(c1) cross apply t.c.nodes('version') as t6(c6) cross apply t6.c6.nodes('page[1]') as t7(c7) Union SELECT NULLIF(t2.c2.value('@mrn','varchar(20)'), '') as [MRN], NULLIF(t2.c2.value('@facility','varchar(10)'), '') as [FACILITY], NULLIF(t3.c3.value('@id','varchar(20)'), '') as [ENCOUNTER], NULLIF(t4.c4.value('@type','varchar(30)'), '') as [DOC_NAME], NULLIF(t4.c4.value('subtitle[1]','varchar(30)'), '') as [SUBTITLE], NULLIF(t4.c4.value('(doc-id/@value)[1]','varchar(max)'), '') as [DOC_ID], NULLIF(t8.c8.value('@imnet-id[1]','varchar(50)'), '1') as [IMNET], NULLIF(t5.c5.value('@number','varchar(max)'), '') as [VersionNumber] from @request.nodes('/request/item[@source="hpf"]/patient') as t2(c2) cross apply t2.c2.nodes('encounter') as t3(c3) cross apply t3.c3.nodes('document') as t4(c4) cross apply t4.c4.nodes('version') as t5(c5) cross apply t5.c5.nodes('page[1]') as t8(c8);
UPDATE a SET a.doc_id = d.doc_id FROM @tmpROIVersion a JOIN cabinet.dbo.documents d ON ( a.facility = d.facility AND a.encounter = d.encounter AND a.doc_name = d.doc_name AND coalesce(a.subtitle, '') = coalesce(d.subtitle, '')) JOIN cabinet.dbo.pages p ON (a.IMNET = p.imnet) JOIN cabinet.dbo.versions v on (p.version_id = v.version_id AND v.VersionNumber = a.VersionNumber) WHERE a.doc_id IS NULL
UPDATE a SET a.doc_id = d.doc_id FROM @tmpROIVersion a JOIN cabinet.dbo.documents d ON ( a.facility = d.facility AND a.mrn = d.mrn AND a.doc_name = d.doc_name AND coalesce(a.subtitle, '') = coalesce(d.subtitle, '')) JOIN cabinet.dbo.pages p ON (a.IMNET = p.imnet) JOIN cabinet.dbo.versions v on (p.version_id = v.version_id AND v.VersionNumber = a.VersionNumber) WHERE a.doc_id IS NULL
insert into @tmpROIPage SELECT NULLIF(t.c.value('@mrn','varchar(20)'), '') as [MRN], NULLIF(t.c.value('@facility','varchar(10)'), '') as [FACILITY], null as [ENCOUNTER], NULLIF(t1.c1.value('@type','varchar(30)'), '') as [DOC_NAME], NULLIF(t1.c1.value('subtitle[1]','varchar(30)'), '') as [SUBTITLE], NULLIF(t1.c1.value('(doc-id/@value)[1]','varchar(max)'), '') as [DOC_ID], NULLIF(t7.c7.value('@imnet-id','varchar(30)'), '') as [IMNET], NULLIF(t6.c6.value('@number','varchar(max)'), '') as [VersionNumber], NULLIF(t7.c7.value('@number','varchar(max)'), '') as [page], NULLIF(t7.c7.value('@content-count','varchar(max)'), '') as [ContentCount], [SelectedForRelease] = case t7.c7.value('@selected-for-release','varchar(10)') when 'true' then 1 when 'false' then 0 else 0 end, [isreleased] = case t7.c7.value('@is-released','varchar(10)') when 'true' then 1 when 'false' then 0 else 0 end from @request.nodes('/request/item[@source="hpf"]/patient') as t(c) cross apply t.c.nodes('global-document') as t1(c1) cross apply t.c.nodes('version') as t6(c6) cross apply t6.c6.nodes('page') as t7(c7) Union SELECT NULLIF(t2.c2.value('@mrn','varchar(20)'), '') as [MRN], NULLIF(t2.c2.value('@facility','varchar(10)'), '') as [FACILITY], NULLIF(t3.c3.value('@id','varchar(20)'), '') as [ENCOUNTER], NULLIF(t4.c4.value('@type','varchar(30)'), '') as [DOC_NAME], NULLIF(t4.c4.value('subtitle[1]','varchar(30)'), '') as [SUBTITLE], NULLIF(t4.c4.value('(doc-id/@value)[1]','varchar(max)'), '') as [DOC_ID], NULLIF(t8.c8.value('@imnet-id','varchar(30)'), '') as [IMNET], NULLIF(t5.c5.value('@number','varchar(max)'), '') as [VersionNumber], NULLIF(t8.c8.value('@number','varchar(max)'), '') as [page], NULLIF(t8.c8.value('@content-count','varchar(max)'), '') as [ContentCount], [SelectedForRelease] = case t8.c8.value('@selected-for-release','varchar(10)') when 'true' then 1 when 'false' then 0 else 0 end, [isreleased] = case t8.c8.value('@is-released','varchar(10)') when 'true' then 1 when 'false' then 0 else 0 end from @request.nodes('/request/item[@source="hpf"]/patient') as t2(c2) cross apply t2.c2.nodes('encounter') as t3(c3) cross apply t3.c3.nodes('document') as t4(c4) cross apply t4.c4.nodes('version') as t5(c5) cross apply t5.c5.nodes('page') as t8(c8);
UPDATE a SET a.doc_id = d.doc_id FROM @tmpROIPage a JOIN cabinet.dbo.documents d ON ( a.facility = d.facility AND a.encounter = d.encounter AND a.doc_name = d.doc_name AND coalesce(a.subtitle, '') = coalesce(d.subtitle, '')) JOIN cabinet.dbo.pages p ON (a.IMNET = p.imnet) JOIN cabinet.dbo.versions v on (p.version_id = v.version_id AND v.VersionNumber = a.VersionNumber) WHERE a.doc_id IS NULL
