insert into [cabinet].[dbo].[ROI_PATIENTS] ([MRN] ,[NAME] ,[SSN] ,[SEX] ,[DOB] ,[FACILITY] ,[EPN] ,[VIP] ,[LOCKOUT] ) OUTPUT inserted.[ROI_Patients_Seq], inserted.[MRN], inserted.[FACILITY] INTO @ROI_PATIENTS_IDX select [MRN] ,[NAME] ,[SSN] ,[SEX] ,[DOB] ,[FACILITY] ,[EPN] ,[VIP] ,[PATIENTLOCKED] from @tmpROIPatient
insert into [cabinet].[dbo].[ROI_ENCOUNTERS] ([ROI_Patients_Seq] ,[ENCOUNTER] ,[MRN] ,[ADMITTED] ,[DISCHARGED] ,[FACILITY] ,[PT_TYPE] ,[SERVICE] ,[LOCKOUT] ,[VIP] ,[HAS_DEFICIENCY] ) OUTPUT inserted.[ROI_Encounters_Seq], inserted.[ROI_Patients_Seq], inserted.[ENCOUNTER], inserted.[FACILITY] INTO @ROI_ENCOUNTERS_IDX select min(b.[ROI_Patients_Seq]), a.[ENCOUNTER], a.[MRN], min(a.[ADMITTED]), max(a.[DISCHARGED]), max(a.[FACILITY]), max(a.[PT_TYPE]), max(a.[SERVICE]), max(cast(a.[LOCKOUT] as int)), max(cast(a.[VIP] as int)), max(cast(a.[HAS_DEFICIENCY] as int)) from @tmpROIEncounter a inner join @ROI_PATIENTS_IDX b on a.MRN = b.[MRN] and a.FACILITY = b.facility group by a.MRN, a.ENCOUNTER, a.FACILITY
-- Global Document insert into [cabinet].[dbo].[ROI_Documents] ( [ROI_Patients_Seq] ,[MRN] ,[FACILITY] ,[DOC_NAME] ,[SUBTITLE] ,[DOC_ID] ,[DOCTYPE_ID] ,[CHART_ORDER] ) OUTPUT inserted.[ROI_Documents_Seq], inserted.[DOC_ID] INTO @ROI_DOCUMENTS_IDX select b.[ROI_Patients_Seq] ,a.[MRN] ,a.[FACILITY] ,a.[DOC_NAME] ,a.[SUBTITLE] ,a.[DOC_ID] ,a.[DOC_TYPE_ID] ,a.[CHART_ORDER] from @tmpROIDocument a join @ROI_PATIENTS_IDX b on a.[MRN] = b.[MRN] and a.[FACILITY] = b.[FACILITY] where a.[ENCOUNTER] is null
insert into [cabinet].[dbo].[ROI_Documents] ( [ROI_Patients_Seq] ,[ROI_Encounters_Seq] ,[ENCOUNTER] ,[MRN] ,[FACILITY] ,[DOC_NAME] ,[SUBTITLE] ,[DOC_ID] ,[DOCTYPE_ID] ,[CHART_ORDER] ) OUTPUT inserted.[ROI_Documents_Seq], inserted.[DOC_ID] INTO @ROI_DOCUMENTS_IDX select b.[ROI_Patients_Seq] ,b.[ROI_Encounters_Seq] ,a.[ENCOUNTER] ,a.[MRN] ,a.[FACILITY] ,a.[DOC_NAME] ,a.[SUBTITLE] ,a.[DOC_ID] ,a.[DOC_TYPE_ID] ,a.[CHART_ORDER] from @tmpROIDocument a join @ROI_ENCOUNTERS_IDX b on a.[ENCOUNTER] = b.[ENCOUNTER] and a.[FACILITY] = b.[FACILITY] where a.[ENCOUNTER] is not NULL
insert into [cabinet].[dbo].[ROI_Versions] ( [ROI_Documents_Seq] ,[DOC_ID] ,[VersionNumber] ) OUTPUT inserted.[ROI_Versions_Seq], inserted.[DOC_ID], inserted.[VersionNumber] INTO @ROI_VERSIONS_IDX select b.[ROI_Documents_Seq] ,a.[DOC_ID] ,a.[VersionNumber] from @tmpROIVersion a join @ROI_DOCUMENTS_IDX b on a.[DOC_ID] = b.[DOC_ID]
insert into [cabinet].[dbo].[ROI_Pages] ( [ROI_Versions_Seq] ,[imnet] ,[page] ,[ContentCount] ,[isreleased] ,[SelectedForRelease] ) OUTPUT inserted.[ROI_Pages_Seq], inserted.[imnet], inserted.[page] INTO @ROI_PAGES_IDX select b.[ROI_Versions_Seq] ,a.[IMNET] ,a.[page] ,a.[ContentCount] ,a.[isreleased] ,a.[SelectedForRelease] from @tmpROIPage a join @ROI_VERSIONS_IDX b on a.[DOC_ID] = b.[DOC_ID] and a.[VersionNumber] = b.[VersionNumber]
insert into @tmpROISupplementarityDocuments SELECT NULLIF(t.c.value('@id','varchar(max)'), '') as [DOCUMENTID], NULLIF(t.c.value('date-of-service[1]','smalldatetime'), '') as [DATEOFSERVICE], NULLIF(t.c.value('encounter[1]','varchar(256)'), '') as [encounter], NULLIF(t.c.value('name[1]','varchar(30)'), '') as [docname], NULLIF(t.c.value('subtitle[1]','varchar(256)'), '') as [subtitle], NULLIF(t.c.value('../../@mrn','varchar(20)'), '') as [MRN], NULLIF(t.c.value('../../@facility','varchar(10)'), '') as [FACILITY], NULLIF(t.c.value('department[1]','varchar(256)'), '') as [DEPARTMENT], NULLIF(t.c.value('page-count[1]','varchar(max)'), '') as [PAGECOUNT], NULLIF(t.c.value('comment[1]','varchar(max)'), '') as [COMMENT], [isreleased] = case t.c.value('is-released[1]','varchar(10)') when 'true' then 1 when 'false' then 0 else 0 end, NULLIF(t.c.value('billing-tier[1]','varchar(max)'), '') as [ROI_BillingTier_Seq], [SelectedForRelease] = case t.c.value('selected-for-release[1]','varchar(10)') when 'true' then 1 when 'false' then 0 else 0 end, NULLIF(t.c.value('facility[1]','varchar(256)'), '') as [DOCFACILITY] from @request.nodes('/request/item[@source="hpf"]/patient/supplemental-encounter/document') as t(c);
insert into [cabinet].[dbo].[ROI_SupplementarityDocumentsCore] ( [ROI_SupplementarityDocuments_Seq] ,[ROI_Patients_Seq] ,[DATEOFSERVICE] ,[encounter] ,[docname] ,[subtitle] ,[MRN] ,[FACILITY] ,[DEPARTMENT] ,[PAGECOUNT] ,[COMMENT] ,[isreleased] ,[ROI_BillingTier_Seq] ,[SelectedForRelease] ,[DOCFACILITY] ,[Created_Dt] ,[Modified_Dt] ,[Created_By_Seq] ,[Modified_By_Seq] ,[Record_Version] ) OUTPUT inserted.[MRN], inserted.[FACILITY], inserted.[ROI_SupplementarityDocuments_Seq], inserted.[ROI_SupplementarityDocumentsCore_Seq] INTO @SupplementarityDocuments_IDX select * from (select (select c.[ROI_SupplementarityDocuments_Seq] from ROI_ConversionMapping_SupplementarityDocuments c join ROI_SupplementarityDocuments sd on (c.ROI_SupplementarityDocuments_Seq = sd.ROI_SupplementarityDocuments_Seq) where a.MRN = sd.[MRN] and a.FACILITY = sd.facility AND a.[DOCUMENTID] = c.document_id AND a.DOCNAME = sd.DOCNAME AND a.DOCFACILITY = sd.DOCFACILITY AND a.SUBTITLE = sd.SUBTITLE AND c.ROI_RequestCore_Seq is null) as ROI_SupplementarityDocuments_Seq ,b.[ROI_Patients_Seq] ,a.[DATEOFSERVICE] ,a.[encounter] ,a.[docname] ,a.[subtitle] ,a.[MRN] ,a.[FACILITY] ,a.[DEPARTMENT] ,a.[PAGECOUNT] ,a.[COMMENT] ,a.[isreleased] ,a.[ROI_BillingTier_Seq] ,a.[SelectedForRelease] ,a.[DOCFACILITY] ,@Created_Dt as Created_Dt ,@Modified_Dt as Modified_Dt ,@Created_By_Seq as Created_By_Seq ,@Modified_By_Seq as Modified_By_Seq ,@Record_Version as Record_Version from @tmpROISupplementarityDocuments a inner join @ROI_PATIENTS_IDX b on a.MRN = b.[MRN] and a.FACILITY = b.facility) d where d.ROI_SupplementarityDocuments_Seq is not null
insert into @tmpROISupplementarityAttachments select NULLIF(t.c.value('@id,','varchar(max)'), '') as [ATTACHMENTID], NULLIF(t.c.value('../../@mrn','varchar(20)'), '') as [MRN], NULLIF(t.c.value('../../@facility','varchar(10)'), '') as [FACILITY], NULLIF(t.c.value('date-of-service[1]','smalldatetime'), '') as [DATEOFSERVICE], NULLIF(t.c.value('encounter[1]','varchar(256)'), '') as [ENCOUNTER], NULLIF(t.c.value('subtitle[1]','varchar(256)'), '') as [SUBTITLE], [isReleased] = case t.c.value('is-released[1]','varchar(10)') when 'true' then 1 when 'false' then 0 else 0 end, NULLIF(t.c.value('attachment-type[1]','varchar(50)'), '') as [TYPE], NULLIF(t.c.value('page-count[1]','varchar(5)'), '') as [PAGECOUNT], NULLIF(t.c.value('file-id[1]','varchar(50)'), '') as [UUID], NULLIF(t.c.value('file-name[1]','varchar(256)'), '') as [FILENAME], NULLIF(t.c.value('file-type[1]','varchar(25)'), '') as [FILETYPE], NULLIF(t.c.value('file-ext[1]','varchar(10)'), '') as [FILEEXT], NULLIF(t.c.value('comment[1]','varchar(max)'), '') as [COMMENT], NULLIF(t.c.value('file-attach-date[1]','smalldatetime'), '') as [ATTACHMENTDATE], NULLIF(t.c.value('billing-tier[1]','varchar(max)'), '') as [ROI_BillingTier_Seq], [SelectedForRelease] = case t.c.value('selected-for-release[1]','varchar(10)') when 'true' then 1 when 'false' then 0 else 0 end, NULLIF(t.c.value('printable-flag[1]','varchar(10)'), '') as [printable_flag], NULLIF(t.c.value('facility[1]','varchar(10)'), '') as [DOCFACILITY] from @request.nodes('/request/item[@source="hpf"]/patient/attachment-encounter/attachment') as t(c);
insert into [cabinet].[dbo].[ROI_SupplementarityAttachmentsCore] ( [ROI_SupplementarityAttachments_Seq] ,[ROI_Patients_Seq] ,[DATEOFSERVICE] ,[ENCOUNTER] ,[SUBTITLE] ,[isReleased] ,[MRN] ,[FACILITY] ,[TYPE] ,[PAGECOUNT] ,[UUID] ,[FILENAME] ,[FILETYPE] ,[FILEEXT] ,[COMMENT] ,[ATTACHMENTDATE] ,[ROI_BillingTier_Seq] ,[SelectedForRelease] ,[printable_flag] ,[DOCFACILITY] ,[Created_Dt] ,[Modified_Dt] ,[Created_By_Seq] ,[Modified_By_Seq] ,[Record_Version] ) OUTPUT inserted.[MRN], inserted.[FACILITY], inserted.[ROI_SupplementarityAttachments_Seq], inserted.[ROI_SupplementarityAttachmentsCore_Seq] INTO @SupplementarityAttachments_IDX select * from (select (select [ROI_SupplementarityAttachments_Seq] from [cabinet].[dbo].ROI_ConversionMapping_SupplementarityAttachments c where a.MRN = c.[MRN] and a.FACILITY = c.facility and a.[ATTACHMENTID] = c.[ATTACHMENT_ID] and c.ROI_RequestCore_Seq is null) as ROI_SupplementarityAttachments_Seq ,b.[ROI_Patients_Seq] ,a.[DATEOFSERVICE] ,a.[ENCOUNTER] ,a.[SUBTITLE] ,a.[isReleased] ,a.[MRN] ,a.[FACILITY] ,a.[TYPE] ,a.[PAGECOUNT] ,a.[UUID] ,a.[FILENAME] ,a.[FILETYPE] ,a.[FILEEXT] ,a.[COMMENT] ,a.[ATTACHMENTDATE] ,a.[ROI_BillingTier_Seq] ,a.[SelectedForRelease] ,a.[printable_flag] ,a.[DOCFACILITY] ,@Created_Dt as Created_Dt ,@Modified_Dt as Modified_Dt ,@Created_By_Seq as Created_By_Seq ,@Modified_By_Seq as Modified_By_Seq ,@Record_Version as Record_Version from @tmpROISupplementarityAttachments a inner join @ROI_PATIENTS_IDX b on a.MRN = b.[MRN] and a.FACILITY = b.facility) d where d.ROI_SupplementarityAttachments_Seq is not null
insert into @tmpROISupplementalPatients select NULLIF(t.c.value('@id','varchar(max)'), '') as [PATIENTID], NULLIF(t.c.value('mrn[1]','varchar(256)'), '') as [MRN], [FACILITY] = case t.c.value('is-freeformfacility[1]','varchar(10)') when 'False' then t.c.value('facility[1]','varchar(10)') when 'true' then NULL else t.c.value('facility[1]','varchar(10)') end, NULLIF(t.c.value('epn[1]','varchar(256)'), '') as [EPN], LASTNAME = case CHARINDEX(',',t.c.value('name[1]','varchar(256)')) when 0 then LTRIM(PARSENAME(REPLACE(t.c.value('name[1]','varchar(256)'),',','.'),1)) else RTRIM(PARSENAME(REPLACE(t.c.value('name[1]','varchar(256)'),',','.'),2)) end, FIRSTNAME = case CHARINDEX(',',t.c.value('name[1]','varchar(256)')) when 0 then NULL else LTRIM(PARSENAME(REPLACE(t.c.value('name[1]','varchar(256)'),',','.'),1)) end, t.c.value('gender[1]','varchar(1)') as gender, NULLIF(t.c.value('dob[1]','datetime'), '') as [DOB], NULLIF(t.c.value('ssn[1]','varchar(27)'), '') as [SSN], [VIP] = case t.c.value('is-vip[1]','varchar(10)') when 'true' then 1 when 'false' then 0 else 0 end, [FreeFormFacility] = case t.c.value('is-freeformfacility[1]','varchar(10)') when 'True' then t.c.value('facility[1]','varchar(256)') else null end from @request.nodes('/request/item[@source="roi"]/patient') as t(c);
insert into @tmpROISupplementalDocuments select NULLIF(t.c.value('../../@id','varchar(max)'), '') as [PATIENTID], NULLIF(t.c.value('@id','varchar(max)'), '') as [DOCUMENTID], NULLIF(t.c.value('date-of-service[1]','smalldatetime'), '') as [DATEOFSERVICE], NULLIF(t.c.value('encounter[1]','varchar(256)'), '') as [ENCOUNTER], NULLIF(t.c.value('name[1]','varchar(30)'), '') as [DOCNAME], NULLIF(t.c.value('subtitle[1]','varchar(256)'), '') as [SUBTITLE], NULLIF(t.c.value('../../@facility','varchar(10)'), '') as [FACILITY], NULLIF(t.c.value('department[1]','varchar(256)'), '') as [DEPARTMENT], NULLIF(t.c.value('page-count[1]','varchar(max)'), '') as [PAGECOUNT], NULLIF(t.c.value('comment[1]','varchar(max)'), '') as [COMMENT], [isreleased] = case t.c.value('is-released[1]','varchar(10)') when 'true' then 1 when 'false' then 0 else 0 end, NULLIF(t.c.value('billing-tier[1]','varchar(max)'), '') as [ROI_BillingTier_Seq], [SelectedForRelease] = case t.c.value('selected-for-release[1]','varchar(10)') when 'true' then 1 when 'false' then 0 else 0 end, NULLIF(t.c.value('facility[1]','varchar(256)'), '') as [DOCFACILITY] from @request.nodes('/request/item[@source="roi"]/patient/supplemental-encounter/document') as t(c);
insert into @tmpROISupplementalAttachments select NULLIF(t.c.value('../../@id','varchar(max)'), '') as [PATIENTID], NULLIF(t.c.value('@id,','varchar(max)'), '') as [ATTACHMENTID], NULLIF(t.c.value('date-of-service[1]','smalldatetime'), '') as [DATEOFSERVICE], NULLIF(t.c.value('encounter[1]','varchar(256)'), '') as [ENCOUNTER], NULLIF(t.c.value('subtitle[1]','varchar(256)'), '') as [SUBTITLE], [isReleased] = case t.c.value('is-released[1]','varchar(max)') when 'true' then 1 when 'false' then 0 else 0 end, NULLIF(t.c.value('attachment-type[1]','varchar(10)'), '') as [TYPE], NULLIF(t.c.value('page-count[1]','varchar(max)'), '') as [PAGECOUNT], NULLIF(t.c.value('file-id[1]','varchar(50)'), '') as [UUID], NULLIF(t.c.value('file-name[1]','varchar(50)'), '') as [FILENAME], NULLIF(t.c.value('file-type[1]','varchar(25)'), '') as [FILETYPE], NULLIF(t.c.value('file-ext[1]','varchar(10)'), '') as [FILEEXT], NULLIF(t.c.value('comment[1]','varchar(max)'), '') as [COMMENT], NULLIF(t.c.value('file-attach-date[1]','smalldatetime'), '') as [ATTACHMENTDATE], NULLIF(t.c.value('billing-tier[1]','varchar(max)'), '') as [ROI_BillingTier_Seq], [SelectedForRelease] = case t.c.value('selected-for-release[1]','varchar(max)') when 'true' then 1 when 'false' then 0 else 0 end, --NULLIF(t.c.value('printable-flag[1]','varchar(max)'), '') as [printable_flag], [printable_flag] = case t.c.value('printable-flag[1]','varchar(10)') when 'true' then 1 when 'false' then 0 else 0 end, NULLIF(t.c.value('facility[1]','varchar(256)'), '') as [DOCFACILITY] from @request.nodes('/request/item[@source="roi"]/patient/attachment-encounter/attachment') as t(c);
insert into [cabinet].[dbo].[ROI_SupplementalPatientsCore] ( [ROI_SupplementalPatients_Seq] ,[MRN] ,[FACILITY] ,[EPN] ,[LASTNAME] ,[FIRSTNAME] ,[GENDER] ,[DOB] ,[SSN] ,[VIP] ,[FreeFormFacility] ,[Created_Dt] ,[Modified_Dt] ,[Created_By_Seq] ,[Modified_By_Seq] ,[Record_Version] ) OUTPUT inserted.[ROI_SupplementalPatientsCore_Seq], inserted.[ROI_SupplementalPatients_Seq] INTO @SupplementalPatients_IDX select (select [ROI_SupplementalPatients_Seq] from [cabinet].[dbo].ROI_ConversionMapping_SupplementalPatient c where a.[PATIENTID] = c.[patient_id] and c.ROI_RequestCore_Seq is null) ,a.[MRN] ,a.[FACILITY] ,a.[EPN] ,a.[LASTNAME] ,a.[FIRSTNAME] ,a.[GENDER] ,a.[DOB] ,a.[SSN] ,a.[VIP] ,a.[FreeFormFacility] ,@Created_Dt ,@Modified_Dt ,@Created_By_Seq ,@Modified_By_Seq ,@Record_Version from @tmpROISupplementalPatients a
insert into [cabinet].[dbo].[ROI_SupplementalDocumentsCore] ( [ROI_SupplementalDocuments_Seq] ,[ROI_SupplementalPatientsCore_Seq] ,[DATEOFSERVICE] ,[ENCOUNTER] ,[DOCNAME] ,[SUBTITLE] ,[FACILITY] ,[DEPARTMENT] ,[PAGECOUNT] ,[isreleased] ,[COMMENT] ,[ROI_BillingTier_Seq] ,[SelectedForRelease] ,[DOCFACILITY] ,[Created_Dt] ,[Modified_Dt] ,[Created_By_Seq] ,[Modified_By_Seq] ,[Record_Version] ) OUTPUT inserted.[ROI_SupplementalDocumentsCore_Seq], inserted.[ROI_SupplementalDocuments_Seq], inserted.[ROI_SupplementalPatientsCore_Seq] INTO @SupplementalDocuments_IDX select (select [ROI_SupplementalDocuments_Seq] from [cabinet].[dbo].[ROI_ConversionMapping_SupplementalDocuments] d where a.[PATIENTID] = d.[patient_id] and a.[DOCUMENTID] = d.[document_id] and d.ROI_RequestCore_Seq is null) ,b.[ROI_SupplementalPatientsCore_Seq] ,a.[DATEOFSERVICE] ,a.[ENCOUNTER] ,a.[DOCNAME] ,a.[SUBTITLE] ,a.[FACILITY] ,a.[DEPARTMENT] ,a.[PAGECOUNT] ,a.[isreleased] ,a.[COMMENT] ,a.[ROI_BillingTier_Seq] ,a.[SelectedForRelease] ,a.[DOCFACILITY] ,@Created_Dt ,@Modified_Dt ,@Created_By_Seq ,@Modified_By_Seq ,@Record_Version from @tmpROISupplementalDocuments a join [cabinet].[dbo].ROI_ConversionMapping_SupplementalPatient c on ( a.[PATIENTID] = c.[patient_id]) join @SupplementalPatients_IDX b on (b.[ROI_SupplementalPatients_Seq] = c.[ROI_SupplementalPatients_Seq]) where c.ROI_RequestCore_Seq is NULL
insert into [cabinet].[dbo].[ROI_SupplementalAttachmentsCore] ( [ROI_SupplementalAttachments_Seq] ,[ROI_SupplementalPatientsCore_Seq] ,[DATEOFSERVICE] ,[ENCOUNTER] ,[SUBTITLE] ,[isReleased] ,[TYPE] ,[PAGECOUNT] ,[UUID] ,[FILENAME] ,[FILETYPE] ,[FILEEXT] ,[COMMENT] ,[ATTACHMENTDATE] ,[ROI_BillingTier_Seq] ,[SelectedForRelease] ,[printable_flag] ,[Created_Dt] ,[Modified_Dt] ,[Created_By_Seq] ,[Modified_By_Seq] ,[Record_Version] ) OUTPUT inserted.[ROI_SupplementalAttachmentsCore_Seq], inserted.[ROI_SupplementalAttachments_Seq], inserted.[ROI_SupplementalPatientsCore_Seq] INTO @SupplementalAttachments_IDX select (select [ROI_SupplementalAttachments_Seq] from [cabinet].[dbo].[ROI_ConversionMapping_SupplementalAttachments] d where a.[PATIENTID] = d.[patient_id] and a.[ATTACHMENTID] = d.[attachment_id] and d.ROI_RequestCore_Seq is null) ,b.[ROI_SupplementalPatientsCore_Seq] ,a.[DATEOFSERVICE] ,a.[ENCOUNTER] ,a.[SUBTITLE] ,a.[isReleased] ,a.[TYPE] ,a.[PAGECOUNT] ,a.[UUID] ,a.[FILENAME] ,a.[FILETYPE] ,a.[FILEEXT] ,a.[COMMENT] ,a.[ATTACHMENTDATE] ,a.[ROI_BillingTier_Seq] ,a.[SelectedForRelease] ,a.[printable_flag] ,@Created_Dt ,@Modified_Dt ,@Created_By_Seq ,@Modified_By_Seq ,@Record_Version from @tmpROISupplementalAttachments a join [cabinet].[dbo].ROI_ConversionMapping_SupplementalPatient c on ( a.[PATIENTID] = c.[patient_id]) join @SupplementalPatients_IDX b on (b.[ROI_SupplementalPatients_Seq] = c.[ROI_SupplementalPatients_Seq]) where c.ROI_RequestCore_Seq is NULL
insert into cabinet.dbo.ROI_RequestCoreEvent (ROI_RequestCore_Seq, Name, Description, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version) select ROI_RequestMain_Seq, Name, Description, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version from cabinet.dbo.ROI_RequestEvent where ROI_RequestMain_Seq = @requestId;
insert into cabinet.dbo.ROI_RequestCoreEvent(ROI_RequestCore_Seq,Name,Description) values(@requestId,'Upgrade Migration','Requests migrated..')
insert into cabinet.dbo.ROI_EXT_SOURCE_DOCUMENTCore (ROI_REQUESTCORE_SEQ, REQUEST_TYPE, REQUEST_STATUS, MRN, ENCOUNTER, FACILITY, ATT_ID, OUTBOUND, REFERENCE_ID, RETRY, RECEIVE_DATE, FULFILL_DATE, OUTPUT_TYPE) select ROI_REQUESTMAIN_SEQ, REQUEST_TYPE, REQUEST_STATUS, MRN, ENCOUNTER, FACILITY, ATT_ID, OUTBOUND, REFERENCE_ID, RETRY, RECEIVE_DATE, FULFILL_DATE, OUTPUT_TYPE from cabinet.dbo.ROI_EXT_SOURCE_DOCUMENT where ROI_REQUESTMAIN_SEQ = @requestId;
insert into cabinet.dbo.ROI_Outbound_StatisticsCore (ROI_RequestCore_Seq, Request_Status, Requested_Dt, Available_Dt, Fulfilled_Dt, Discharge_Dt, Cancelled_Dt, TAHours, TotalDays, WeekendDays, MRN, Encounter, Facility, HPFMUDocumentType, UserInstanceId, ExternalSource, Report_Sname, Requested_For, Document_Type, Pat_Seq, Available_By, CPI_Seq, PatientFirstName, PatientLastName, PatientDOB, PatientSex, Outbound) select ROI_RequestMain_Seq, Request_Status, Requested_Dt, Available_Dt, Fulfilled_Dt, Discharge_Dt, Cancelled_Dt, TAHours, TotalDays, WeekendDays, MRN, Encounter, Facility, HPFMUDocumentType, UserInstanceId, ExternalSource, Report_Sname, Requested_For, Document_Type, Pat_Seq, Available_By, CPI_Seq, PatientFirstName, PatientLastName, PatientDOB, PatientSex, Outbound from cabinet.dbo.ROI_Outbound_Statistics where ROI_RequestMain_Seq = @requestId;
-- Update Mapping insert into [cabinet].[dbo].[ROI_RequestCoretoROI_Patients] (ROI_RequestCore_Seq, ROI_Patients_Seq) select @requestId, [ROI_Patients_Seq] from @ROI_PATIENTS_IDX
insert into [cabinet].[dbo].[ROI_RequestCoretoROI_SupplementalPatientsCore] (ROI_RequestCore_Seq, [ROI_SupplementalPatientsCore_Seq]) select @requestId, [ROI_SupplementalPatientsCore_Seq] from @SupplementalPatients_IDX
-- Update Conversion Mapping insert into [cabinet].[dbo].[ROI_ConversionMapping_SupplementarityDocuments] ( [ROI_RequestCore_Seq] ,[MRN] ,[FACILITY] ,[document_id] ,[ROI_SupplementarityDocuments_Seq] ,[ROI_SupplementarityDocumentsCore_Seq]) select @requestId, a.[MRN], a.[FACILITY], b.[document_id], a.[ROI_SupplementarityDocuments_Seq], a.[ROI_SupplementarityDocumentsCore_Seq] from @SupplementarityDocuments_IDX a join [cabinet].[dbo].[ROI_ConversionMapping_SupplementarityDocuments] b on a.ROI_SupplementarityDocuments_Seq = b.ROI_SupplementarityDocuments_Seq where b.[ROI_RequestCore_Seq] is null
insert into [cabinet].[dbo].[ROI_ConversionMapping_SupplementarityAttachments] ([ROI_RequestCore_Seq] ,[MRN] ,[FACILITY] ,[attachment_id] ,[ROI_SupplementarityAttachments_Seq] ,[ROI_SupplementarityAttachmentsCore_Seq]) select @requestId, a.[MRN], a.[FACILITY], b.[attachment_id], a.[ROI_SupplementarityAttachments_Seq], a.[ROI_SupplementarityAttachmentsCore_Seq] from @SupplementarityAttachments_IDX a join [cabinet].[dbo].ROI_ConversionMapping_SupplementarityAttachments b on a.ROI_SupplementarityAttachments_Seq = b.ROI_SupplementarityAttachments_Seq where b.[ROI_RequestCore_Seq] is null
insert into [cabinet].[dbo].[ROI_ConversionMapping_SupplementalPatient] ([ROI_RequestCore_Seq] ,[patient_id] ,[ROI_SupplementalPatients_Seq] ,[ROI_SupplementalPatientsCore_Seq]) select @requestId, b.[patient_id], a.[ROI_SupplementalPatients_Seq], a.[ROI_SupplementalPatientsCore_Seq] from @SupplementalPatients_IDX a join [cabinet].[dbo].ROI_ConversionMapping_SupplementalPatient b on a.ROI_SupplementalPatients_Seq = b.ROI_SupplementalPatients_Seq where b.[ROI_RequestCore_Seq] is null
insert into [cabinet].[dbo].[ROI_ConversionMapping_SupplementalDocuments] ([ROI_RequestCore_Seq] ,[patient_id] ,[document_id] ,[ROI_SupplementalDocuments_Seq] ,[ROI_SupplementalDocumentsCore_Seq]) select @requestId, b.[patient_id], b.[document_id], a.[ROI_SupplementalDocuments_Seq], a.[ROI_SupplementalDocumentsCore_Seq] from @SupplementalDocuments_IDX a join [cabinet].[dbo].ROI_ConversionMapping_SupplementalDocuments b on a.ROI_SupplementalDocuments_Seq = b.ROI_SupplementalDocuments_Seq where b.[ROI_RequestCore_Seq] is null
insert into [cabinet].[dbo].[ROI_ConversionMapping_SupplementalAttachments] ([ROI_RequestCore_Seq] ,[patient_id] ,[attachment_id] ,[ROI_SupplementalAttachments_Seq] ,[ROI_SupplementalAttachmentsCore_Seq]) select @requestId, b.[patient_id], b.[attachment_id], a.[ROI_SupplementalAttachments_Seq], a.[ROI_SupplementalAttachmentsCore_Seq] from @SupplementalAttachments_IDX a join [cabinet].[dbo].ROI_ConversionMapping_SupplementalAttachments b on a.ROI_SupplementalAttachments_Seq = b.ROI_SupplementalAttachments_Seq where b.[ROI_RequestCore_Seq] is null

		
SELECT TOP 1
	@reqDelCharges = RequestDeliveryChargesXML,
	@Created_Dt = Created_Dt,
	@Created_By_Seq = Created_By_Seq,
	@Modified_By_Seq = Modified_By_Seq,
	@Modified_Dt = Modified_Dt,
	@Record_Version = Record_Version
FROM ROI_RequestDeliveryCharges
WHERE ROI_RequestDelivery_Seq IN
	(SELECT ROI_RequestDelivery_Seq FROM ROI_RequestDelivery WHERE ROI_RequestMain_Seq = @requestId)
		AND isInvoiced = 0 ORDER BY Created_Dt DESC
IF(@reqDelCharges IS NOT NULL)
BEGIN
SELECT
@salesTaxPercentage = REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(facility/sales-tax)[1]','varchar(max)'),0.00), '$',''), ')', ''), '(', '-'),',',''),
@facilityCode = ISNULL(p.value('(facility/code)[1]','varchar(10)'), @defaultFacilityCode),
@facilityName = ISNULL(p.value('(facility/name)[1]','varchar(25)'), @defaultFacilityName),
@applySalesTax = CASE p.value('apply-salestax[1]','varchar(10)') WHEN 'True' THEN 1  WHEN 'False' THEN 0 ELSE 0 END
FROM @request.nodes('/request') as p(p);

INSERT INTO cabinet.dbo.ROI_RequestCoreCharges(ROI_RequestCore_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, Release_Date, Release_Cost, Total_Pages, Total_Pages_Released, Salestax_Percentage, Billing_Type, FACILITY_CODE, FACILITY_NAME, Apply_SalesTax, DisplayBillingInfo, Unbillable)
SELECT
	@requestid, @Created_Dt, @Created_By_Seq, @Modified_Dt, @Modified_By_Seq, @Record_Version,
	NULLIF(p.value('(attribute[@name="release-date"]/@value)[1]','smalldatetime'), @Modified_Dt) as Release_Date,
	REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(attribute[@name="release-cost"]/@value)[1]','varchar(max)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Release_Cost,
	ISNULL(p.value('(attribute[@name="total-pages"]/@value)[1]','varchar(max)'),0) as Total_Pages,
	ISNULL(p.value('(attribute[@name="total-pages-released"]/@value)[1]','varchar(max)'),0) as Total_Pages_Released,
	@salesTaxPercentage,
	p.value('(../../release-item[@type="charges"]/release-item[@type="FeeCharge"]/attribute[@name="billing-type"]/@value)[1]','varchar(50)') as Billing_Type,
	@facilityCode,
	@facilityName,
	@applySalesTax,
	1,
	1
FROM @reqDelCharges.nodes('/release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]') as p(p);
SELECT @rcChargesId = SCOPE_IDENTITY();

INSERT INTO cabinet.dbo.ROI_RequestCoreChargesDocument(ROI_RequestCoreCharges_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, Amount, Copies, TotalPages, Pages, BillingTierName, BillingTierId, ReleaseCount, isElectronic, RemoveBasecharge, Has_Salestax, Salestax_Amount)
SELECT
	@rcChargesId, @Created_Dt, @Created_By_Seq, @Modified_Dt, @Modified_By_Seq, @Record_Version,
	REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="amount"]/@value)[1]','varchar(max)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Amount,
	ISNULL(p.value('(./attribute[@name="copies"]/@value)[1]','varchar(max)'),0) as Copies,
	ISNULL(p.value('(./attribute[@name="total-pages"]/@value)[1]','varchar(max)'),0) as TotalPages,
	ISNULL(p.value('(./attribute[@name="pages"]/@value)[1]','varchar(max)'),0) as Pages,
	ISNULL(p.value('(./attribute[@name="billingtier-name"]/@value)[1]','varchar(256)'),'') as BillingTierName,
	ISNULL(p.value('(./attribute[@name="billingtier-id"]/@value)[1]','varchar(max)'),0) as BillingTierId,
	ISNULL(p.value('(./attribute[@name="release-count"]/@value)[1]','varchar(max)'),0) as ReleaseCount,
	case p.value('(./attribute[@name="is-electronic"]/@value)[1]','varchar(1)')  when 'T' then 1 else 0 end as isElectronic,
	case p.value('(./attribute[@name="remove-basecharge"]/@value)[1]','varchar(1)')  when 'T' then 1 else 0 end as RemoveBasecharge,
	case p.value('(./attribute[@name="has-salestax"]/@value)[1]','varchar(1)')  when 'T' then 1 else 0 end as Has_Salestax,
	REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="salestax-amount"]/@value)[1]','varchar(max)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Salestax_Amount
FROM @reqDelCharges.nodes('/release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="DocumentCharge"]/release-item') as p(p);

INSERT INTO cabinet.dbo.ROI_RequestCoreChargesFee(ROI_RequestCoreCharges_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, Amount, IsCustomFee, FeeType, Has_Salestax, Salestax_Amount)
SELECT
	@rcChargesId, @Created_Dt, @Created_By_Seq, @Modified_Dt, @Modified_By_Seq, @Record_Version,
	REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="amount"]/@value)[1]','varchar(max)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Amount,
	case p.value('(./attribute[@name="is-custom-fee"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as IsCustomFee,
	ISNULL(p.value('(./attribute[@name="feetype"]/@value)[1]','varchar(50)'),'') as FeeType,
	case p.value('(./attribute[@name="has-salestax"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as Has_Salestax,
	REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="salestax-amount"]/@value)[1]','varchar(max)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Salestax_Amount
FROM @reqDelCharges.nodes('/release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="FeeCharge"]/release-item') as p(p);

INSERT INTO cabinet.dbo.ROI_RequestCoreChargesShipping(ROI_RequestCoreCharges_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, ShippingCharge, AddressType, Address1, Address2, Address3, City, State, PostalCode, ShippingUrl, ShippingWeight, TrackingNumber, WillReleaseShipped, ShippingMethod, OutputMethod, ShippingMethodId, Nonprintable_Attachment_Queue, Country_Code, Country_Name)
SELECT
	@rcChargesId, @Created_Dt, @Created_By_Seq, @Modified_Dt, @Modified_By_Seq, @Record_Version,
	REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(../release-item[@type="charges"]/release-item[@type="shipping-charge"]/attribute[@name="shipping-charge"]/@value)[1]','varchar(max)'),0.00), '$',''), ')', ''), '(', '-'),',','') as ShippingCharge,
	p.value('(./attribute[@name="address-type"]/@value)[1]','varchar(20)') as AddressType,
	p.value('(./attribute[@name="address1"]/@value)[1]','varchar(256)') as Address1,
	p.value('(./attribute[@name="address2"]/@value)[1]','varchar(256)') as Address2,
	p.value('(./attribute[@name="address3"]/@value)[1]','varchar(256)') as Address3,
	p.value('(./attribute[@name="city"]/@value)[1]','varchar(50)') as City,
	p.value('(./attribute[@name="state"]/@value)[1]','varchar(20)') as State,
	p.value('(./attribute[@name="postalcode"]/@value)[1]','varchar(20)') as PostalCode,
	p.value('(./attribute[@name="shipping-url"]/@value)[1]','varchar(50)') as ShippingUrl,
	ISNULL(p.value('(./attribute[@name="shipping-weight"]/@value)[1]','varchar(max)'),0) as ShippingWeight,
	p.value('(./attribute[@name="tracking-number"]/@value)[1]','varchar(35)') as TrackingNumber,
	case p.value('(./attribute[@name="will-release-shipped"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as WillReleaseShipped,
	p.value('(./attribute[@name="shipping-method"]/@value)[1]','varchar(35)') as ShippingMethod,
	p.value('(./attribute[@name="output-method"]/@value)[1]','varchar(35)') as OutputMethod,
	p.value('(./attribute[@name="shipping-method-id"]/@value)[1]','bigint') as ShippingMethodId,
	null, null, null
FROM @reqDelCharges.nodes('/release-item[@type="billing-info"]/release-item[@type="shipping-info"]') as p(p);

INSERT INTO cabinet.dbo.ROI_RequestCoreChargesSalesTaxReason(ROI_RequestCoreCharges_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, Reason, Reason_Date)
SELECT
	@rcChargesId, @Created_Dt, @Created_By_Seq, @Modified_Dt, @Modified_By_Seq, @Record_Version,
	ISNULL(p.value('(attribute[@name="reason"]/@value)[1]','varchar(256)'),'') as Reason,
	ISNULL(p.value('(attribute[@name="date"]/@value)[1]','smalldatetime'),@Created_Dt) as Reason_Date
FROM @reqDelCharges.nodes('/release-item[@type="billing-info"]/release-item[@type="salestax-reason"]/release-item') as p(p);
END

insert into @tmpRelease select ROI_RequestDelivery_Seq, p.value('(./@is-released)[1]','varchar(10)') as isReleased, Created_Dt as releaseDate from ROI_RequestDelivery cross apply RequestDeliveryXML.nodes('/release') as p(p) where ROI_RequestMain_Seq=@requestId
insert into @tmpInvoice select ROI_RequestDelivery_Seq, max(ROI_RequestDeliveryCharges_Seq) as invoiceId, 'Invoice' as Type from ROI_RequestDeliveryCharges cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-doc"]') as p(p) where isInvoiced=1 and ROI_RequestDelivery_Seq in (select ROI_RequestDelivery_Seq from @tmpRelease) and p.value('(./attribute[@name="type"]/@value)[1]','varchar(10)')='Invoice' group by ROI_RequestDelivery_Seq
insert into @tmpInvoiceMigrated select ROI_RequestDelivery_Seq, ROI_RequestDeliveryCharges_Seq from ROI_RequestDeliveryCharges where isInvoiced=1 and ROI_RequestDelivery_Seq in (select ROI_RequestDelivery_Seq from @tmpRelease) and RequestDeliveryChargesXML.value('(/release-item/attribute[@name="type"]/@value)[1]','varchar(max)')='Invoice'
insert into @tmpDraftInvoice select ROI_RequestDelivery_Seq, max(ROI_RequestDeliveryCharges_Seq) as draftInvoiceId from ROI_RequestDeliveryCharges where isInvoiced=0 and ROI_RequestDelivery_Seq in (select ROI_RequestDelivery_Seq from @tmpRelease) group by ROI_RequestDelivery_Seq
insert into @tmprelease_invoice_mapping(releaseid, isReleased, releaseDate, invoiceid, draftinvoiceid, Type) select r.ROI_RequestDelivery_Seq , r.isReleased, r.releaseDate, i.ROI_RequestDeliveryCharges_Seq as invoiceid, di.ROI_RequestDeliveryCharges_Seq as draftinvoiceid, i.Type from @tmpRelease r left join @tmpInvoice i on r.ROI_RequestDelivery_Seq = i.ROI_RequestDelivery_Seq left join @tmpDraftInvoice di on r.ROI_RequestDelivery_Seq = di.ROI_RequestDelivery_Seq where (r.isReleased <> 'False' or i.ROI_RequestDeliveryCharges_Seq is not null) and (r.isReleased <> 'False')
insert into cabinet.dbo.ROI_RequestCoreDeliveryCharges (ROI_RequestCore_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, Previously_Released_Cost, Release_Date, Total_Pages, Total_Pages_Released, Salestax_Total_Amount, Salestax_Percentage_BillingLoc, Letter_Template_Name, Request_Status, Request_Date, LetterTemplate_FileId, Type, Invoice_Prebill_Date, Invoice_Due_Date, Resend_Date, Output_Method, Queue_Password, Invoice_Salestax, Base_Charge, Balance_Due, FACILITY_CODE, FACILITY_NAME, Invoice_Balance_Due, Is_Released, Billing_Type, Apply_SalesTax, Notes, Invoice_Due_Days, Overwrite_Due_Date, Unbillable, PreBill_Status, Unbillable_Amount) output inserted.ROI_RequestCoreDeliveryCharges_Seq, inserted.Created_By_Seq, inserted.ROI_RequestCore_Seq into @ROI_RequestCoreDeliveryCharges_IDX select @requestid, rcdc2.Created_Dt, rcdc2.Created_By_Seq, rcdc2.Modified_Dt, rcdc2.Modified_By_Seq, rcdc2.Record_Version, rcdc2.Previously_Released_Cost, rcdc2.Release_Date, rcdc2.Total_Pages, rcdc2.Total_Pages_Released, 0.00 as Salestax_Total_Amount, 0.00 as Salestax_Percentage_BillingLoc, rcdc1.Letter_Template_Name, rcdc1.Request_Status, rcdc1.Request_Date, rcdc1.LetterTemplate_FileId, rcdc1.Type, rcdc2.Modified_Dt as Invoice_Prebill_Date, dateadd(day, @defaultInvoiceDueDays, rcdc1.Created_Dt) as Invoice_Due_Date, NULL as Resend_Date, rcdc1.Output_Method, rcdc1.Queue_Password, 0.00 as Invoice_Salestax, rcdc2.Release_Cost as Base_Charge, rcdc1.Balance_Due, @defaultFacilityCode as FACILITY_CODE, @defaultFacilityName as FACILITY_NAME, rcdc2.Release_Cost as Invoice_Balance_Due, rcdc2.Is_Released, rcdc2.Billing_Type, 0 as Apply_SalesTax, rcdc1.Notes, @defaultInvoiceDueDays as Invoice_Due_Days, 0 as Overwrite_Due_Date, 1 as Unbillable, null as Prebill_Status, 0.00 as Unbillable_Amount from ( select rim.releaseid, irdc.Created_Dt, p.value('(./attribute[@name="lettertemplate-name"]/@value)[1]','varchar(50)') as Letter_Template_Name, ISNULL(p.value('(./attribute[@name="request-status"]/@value)[1]','varchar(50)'),'') as Request_Status, p.value('(./attribute[@name="request-dt"]/@value)[1]','smalldatetime') as Request_Date, ISNULL(p.value('(./attribute[@name="lettertemplate-fileid"]/@value)[1]','int'),1) as LetterTemplate_FileId, ISNULL(p.value('(./attribute[@name="type"]/@value)[1]','varchar(10)'),'') as Type, ISNULL(p.value('(./attribute[@name="output-method"]/@value)[1]','varchar(50)'),'') as Output_Method, p.value('(./attribute[@name="queue-password"]/@value)[1]','varchar(50)') as Queue_Password, (select stuff( (select '~'+ c.value('./@value[1]','varchar(max)') from [RequestDeliveryChargesXML].nodes('/release-item[@type="billing-doc"]/release-item[@type="notes"]/release-item/attribute[@name="description"]') as t(c) FOR XML PATH('')),1,1,'')) as Notes, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="balance-due"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Balance_Due from ROI_RequestDeliveryCharges irdc join @tmprelease_invoice_mapping rim on irdc.ROI_RequestDeliveryCharges_Seq = rim.invoiceid cross apply irdc.RequestDeliveryChargesXML.nodes('/release-item[@type="billing-doc"]') as p(p) union all select releaseid, releaseDate, null, '', releaseDate, 1, 'Invoice', '', null, null,'0.00' from @tmprelease_invoice_mapping where invoiceid is null) rcdc1 join ( select rim.releaseid, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="previously-released-cost"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Previously_Released_Cost, p.value('(release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="release-date"]/@value)[1]','smalldatetime') as Release_Date, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="release-cost"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Release_Cost, ISNULL(p.value('(release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="total-pages"]/@value)[1]','int'),0) as Total_Pages, ISNULL(p.value('(release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="total-pages-released"]/@value)[1]','int'),0) as Total_Pages_Released, drdc.isReleased as Is_Released, p.value('(release-item[@type="charges"]/release-item[@type="FeeCharge"]/attribute[@name="billing-type"]/@value)[1]','varchar(50)') as Billing_Type, rim.releaseid as Created_By_Seq, drdc.Created_Dt, drdc.Modified_By_Seq, drdc.Modified_Dt, drdc.Record_Version from ROI_RequestDeliveryCharges drdc join @tmprelease_invoice_mapping rim on drdc.ROI_RequestDeliveryCharges_Seq = rim.draftinvoiceid cross apply drdc.RequestDeliveryChargesXML.nodes('/release-item[@type="billing-info"]') as p(p)) rcdc2 on rcdc1.releaseid = rcdc2.releaseid order by rcdc2.releaseid
update idx1 set newinvoiceid=idx2.ROI_RequestCoreDeliveryCharges_Seq from @tmprelease_invoice_mapping idx1 join @ROI_RequestCoreDeliveryCharges_IDX idx2 on idx1.releaseid = idx2.releaseid;
insert into cabinet.dbo.ROI_RequestCoreDeliveryChargesDocument (ROI_RequestCoreDeliveryCharges_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, Amount, Copies, TotalPages, Pages, BillingTierName, BillingTierId, ReleaseCount, isElectronic, RemoveBasecharge, Has_Salestax, Salestax_Amount) select (select ROI_RequestCoreDeliveryCharges_Seq from @ROI_RequestCoreDeliveryCharges_IDX where releaseid = rim.releaseid), drdc.Created_Dt, drdc.Created_By_Seq, drdc.Modified_Dt, drdc.Modified_By_Seq, drdc.Record_Version, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="amount"]/@value)[1]','varchar(20)'), 0.00), '$',''),')',''), '(', '-'),',','') as Amount, ISNULL(p.value('(./attribute[@name="copies"]/@value)[1]','varchar(20)'),0) as Copies, ISNULL(p.value('(./attribute[@name="total-pages"]/@value)[1]','varchar(20)'),0) as TotalPages, ISNULL(p.value('(./attribute[@name="pages"]/@value)[1]','varchar(20)'),0) as Pages, ISNULL(p.value('(./attribute[@name="billingtier-name"]/@value)[1]','varchar(256)'),'') as BillingTierName, ISNULL(p.value('(./attribute[@name="billingtier-id"]/@value)[1]','varchar(20)'),0) as BillingTierId, ISNULL(p.value('(./attribute[@name="release-count"]/@value)[1]','varchar(20)'),0) as ReleaseCount, case p.value('(./attribute[@name="is-electronic"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as IsElectronic, case p.value('(./attribute[@name="remove-basecharge"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as RemoveBaseCharge, 0 as Has_Salestax, 0.00 as SalesTax_Amount from ROI_RequestDeliveryCharges drdc join @tmprelease_invoice_mapping rim on drdc.ROI_RequestDeliveryCharges_Seq = rim.draftinvoiceid cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="DocumentCharge"]/release-item') as p(p);
insert into cabinet.dbo.ROI_RequestCoreDeliveryChargesFee (ROI_RequestCoreDeliveryCharges_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, Amount, IsCustomFee, FeeType, Has_Salestax, Salestax_Amount) select (select ROI_RequestCoreDeliveryCharges_Seq from @ROI_RequestCoreDeliveryCharges_IDX where releaseid = rim.releaseid), drdc.Created_Dt, drdc.Created_By_Seq, drdc.Modified_Dt, drdc.Modified_By_Seq, drdc.Record_Version, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="amount"]/@value)[1]','varchar(max)'), 0.00), '$',''),')',''), '(', '-'),',','') as Amount, case p.value('(./attribute[@name="is-custom-fee"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as IsCustomFee, p.value('(./attribute[@name="feetype"]/@value)[1]','varchar(50)') as FeeType, 0 as Has_Salestax, 0.00 as SalesTax_Amount from ROI_RequestDeliveryCharges drdc join @tmprelease_invoice_mapping rim on drdc.ROI_RequestDeliveryCharges_Seq = rim.draftinvoiceid cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="FeeCharge"]/release-item') as p(p);
insert into cabinet.dbo.ROI_RequestCoreDeliveryChargesShipping (ROI_RequestCoreDeliveryCharges_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, ShippingCharge, AddressType, Address1, Address2, Address3, City, State, PostalCode, ShippingUrl, ShippingWeight, TrackingNumber, WillReleaseShipped, ShippingMethod, OutputMethod, ShippingMethodId) select (select ROI_RequestCoreDeliveryCharges_Seq from @ROI_RequestCoreDeliveryCharges_IDX where releaseid = rim.releaseid), drdc.Created_Dt, drdc.Created_By_Seq, drdc.Modified_Dt, drdc.Modified_By_Seq, drdc.Record_Version, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(../release-item[@type="charges"]/release-item[@type="shipping-charge"]/attribute[@name="shipping-charge"]/@value)[1]','varchar(max)'),0.00), '$',''), ')', ''), '(', '-'),',','') as ShippingCharge, p.value('(./attribute[@name="address-type"]/@value)[1]','varchar(20)') as AddressType, p.value('(./attribute[@name="address1"]/@value)[1]','varchar(256)') as Address1, p.value('(./attribute[@name="address2"]/@value)[1]','varchar(256)') as Address2, p.value('(./attribute[@name="address3"]/@value)[1]','varchar(256)') as Address3, p.value('(./attribute[@name="city"]/@value)[1]','varchar(50)') as City, p.value('(./attribute[@name="state"]/@value)[1]','varchar(20)') as State, p.value('(./attribute[@name="postalcode"]/@value)[1]','varchar(20)') as PostalCode, p.value('(./attribute[@name="shipping-url"]/@value)[1]','varchar(50)') as ShippingUrl, ISNULL(p.value('(./attribute[@name="shipping-weight"]/@value)[1]','varchar(max)'),0) as ShippingWeight, p.value('(./attribute[@name="tracking-number"]/@value)[1]','varchar(35)') as TrackingNumber, case p.value('(./attribute[@name="will-release-shipped"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as WillReleaseShipped, p.value('(./attribute[@name="shipping-method"]/@value)[1]','varchar(35)') as ShippingMethod, p.value('(./attribute[@name="output-method"]/@value)[1]','varchar(35)') as OutputMethod, p.value('(./attribute[@name="shipping-method-id"]/@value)[1]','bigint') as ShippingMethodId from ROI_RequestDeliveryCharges drdc join @tmprelease_invoice_mapping rim on drdc.ROI_RequestDeliveryCharges_Seq = rim.draftinvoiceid cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-info"]/release-item[@type="shipping-info"]') as p(p);
insert into @tmpROI_RequestCoreDeliveryChargesInvoicePatients select (select ROI_RequestCoreDeliveryCharges_Seq from @ROI_RequestCoreDeliveryCharges_IDX where releaseid = rim.releaseid), t.c.value('(attribute[@name="patientmrn"]/@value)[1]','varchar(20)') as mrn, t.c.value('(attribute[@name="facility"]/@value)[1]','varchar(10)') as facility, t.c.value('(attribute[@name="patientname"]/@value)[1]','varchar(40)') as patientName from ROI_RequestDeliveryCharges irdc join @tmprelease_invoice_mapping rim on irdc.ROI_RequestDeliveryCharges_Seq = rim.invoiceid cross apply [RequestDeliveryChargesXML].nodes('/release-item[@type="billing-doc"]/release-item[@type="requestItem"]/release-item') t(c)
INSERT INTO ROI_RequestCoreDeliveryChargesInvoicePatients ( ROI_RequestCoreDeliveryCharges_Seq ,ROI_SupplementalPatientsCore_Seq , ROI_Patients_Seq ) select a.ROI_RequestCoreDeliveryCharges_Seq, null as ROI_SupplementalPatientsCore_Seq, b.ROI_Patients_Seq as ROI_Patients_Seq from @tmpROI_RequestCoreDeliveryChargesInvoicePatients a join ROI_Patients b on (a.patientName = b.Name and a.MRN = b.MRN and a.Facility = b.Facility) where b.ROI_Patients_seq in (select ROI_Patients_seq from ROI_RequestCoretoROI_Patients where ROI_RequestCore_Seq = @requestId) Union select a.ROI_RequestCoreDeliveryCharges_Seq, b.ROI_SupplementalPatientsCore_Seq, NULL as ROI_Patients_Seq from @tmpROI_RequestCoreDeliveryChargesInvoicePatients a join ROI_SupplementalPatientsCore b on (a.patientName = (b.lastName + ', ' + b.firstName) and a.MRN = b.MRN and a.Facility = b.Facility) where b.ROI_SupplementalPatientsCore_Seq in (select ROI_SupplementalPatientsCore_Seq from ROI_RequestCoretoROI_SupplementalPatientsCore where ROI_RequestCore_Seq = @requestId);
insert into ROI_RequestCoreDeliveryChargesMigrated(ROI_RequestDeliveryCharges_Seq, ROI_RequestCoreDeliveryCharges_Seq, ROI_RequestCore_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, Request_Password, Queue_Password, Balance_Due) select idx2.ROI_RequestDeliveryCharges_Seq, idx1.newinvoiceid as ROI_RequestCoreDeliveryCharges_Seq, @requestId as ROI_RequestCore_Seq, rdc.Created_Dt, rdc.Created_By_Seq, rdc.Modified_Dt, rdc.Modified_By_Seq, rdc.Record_Version, (select ReqPassword from @tmpRequestCore) as Request_Password, p.value('(./attribute[@name="queue-password"]/@value)[1]','varchar(20)') as Queue_Password, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="balance-due"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Balance_Due from @tmprelease_invoice_mapping idx1 right join @tmpInvoiceMigrated idx2 on idx1.releaseid=idx2.ROI_RequestDelivery_Seq join ROI_RequestDeliveryCharges rdc on rdc.ROI_RequestDeliveryCharges_Seq = idx2.ROI_RequestDeliveryCharges_Seq cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-doc"]') as p(p)
insert into @tmpPaymentAdjustments select ROI_RequestDeliveryCharges_Seq, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="amount"]/@value)[1]','varchar(max)'), 0.00), '$',''),')',''), '(', '-'),',','') as Amount, p.value('(./attribute[@name="payment-mode"]/@value)[1]','varchar(50)') as PaymentMode, p.value('(./attribute[@name="description"]/@value)[1]','varchar(256)') as Description, p.value('(./attribute[@name="date"]/@value)[1]','datetime') as Date, p.value('(./attribute[@name="transaction-type"]/@value)[1]','varchar(50)') as TransactionType, p.value('(./attribute[@name="is-debit"]/@value)[1]','varchar(10)') as IsDebit, Created_By_Seq, Modified_By_Seq from ROI_RequestDeliveryCharges cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="request-transaction"]/release-item') as p(p) where ROI_RequestDeliveryCharges_Seq in (select ROI_RequestDeliveryCharges_Seq from @tmpDraftInvoice);
insert into @tmpPaymentAdjustments1(draftinvoiceid, Amount, PaymentMode, Description, Date, TransactionType, IsDebit, Created_By_Seq, Modified_By_Seq) select e.* from ( select MIN(draftinvoiceid) as draftinvoiceid, DATE from @tmpPaymentAdjustments group by date ) tmp join @tmpPaymentAdjustments e on e.draftinvoiceid = tmp.draftinvoiceid and e.Date = tmp.Date;
if exists( select 1 from @tmpRequestCore where RequestStatus in ('Canceled','Denied') ) begin --CR382488 delete from @tmpPaymentAdjustments1 where TransactionType='Adjustment'; end
insert into ROI_RequestCoreDeliveryChargesFee(ROI_RequestCoreDeliveryCharges_Seq, Created_By_Seq, Created_Dt, Modified_By_Seq, Modified_Dt, Amount, IsCustomFee, FeeType, Has_Salestax, Salestax_Amount) select rim.newinvoiceid, idx1.Created_By_Seq, idx1.Date, idx1.Modified_By_Seq, idx1.Date, idx1.amount, 1, 'Migration - Debit Adj', 0, 0.00 from @tmpPaymentAdjustments1 idx1 join @tmprelease_invoice_mapping rim on rim.draftinvoiceid=idx1.draftinvoiceid where TransactionType='Adjustment' and IsDebit='True';
set @requestDeliveryCharges_id = (select top 1 ROI_requestCoreDeliveryCharges_Seq from @ROI_RequestCoreDeliveryCharges_IDX order by ROI_RequestCoreDeliveryCharges_Seq) while @requestDeliveryCharges_id is not null begin set @base_charge = ((select COALESCE(SUM(ShippingCharge),0.0) from ROI_RequestCoreDeliveryChargesShipping where ROI_RequestCoreDeliveryCharges_seq = @requestDeliveryCharges_id) + (select COALESCE(SUM(amount),0.0) from ROI_RequestCoreDeliveryChargesDocument where ROI_RequestCoreDeliveryCharges_seq = @requestDeliveryCharges_id) + (select COALESCE(SUM(amount),0.0) from ROI_RequestCoreDeliveryChargesFee where ROI_RequestCoreDeliveryCharges_seq = @requestDeliveryCharges_id)) update ROI_RequestCoreDeliveryCharges set Base_Charge = @base_charge where ROI_RequestCoreDeliveryCharges_Seq = @requestDeliveryCharges_id set @requestDeliveryCharges_id = (select top 1 ROI_requestCoreDeliveryCharges_Seq from @ROI_RequestCoreDeliveryCharges_IDX where ROI_RequestCoreDeliveryCharges_Seq >@requestDeliveryCharges_id order by ROI_RequestCoreDeliveryCharges_Seq) end
-- update rcdc set Base_Charge=Base_Charge+isnull((select SUM(amount) from @tmpPaymentAdjustments1 idx1 join @tmprelease_invoice_mapping idx2 on idx1.draftinvoiceid=idx2.draftinvoiceid and idx1.TransactionType='Adjustment' and idx1.IsDebit='True' and idx2.newinvoiceid=rcdc.ROI_RequestCoreDeliveryCharges_Seq),0) from ROI_RequestCoreDeliveryCharges rcdc where rcdc.ROI_RequestCoreDeliveryCharges_Seq in (select newinvoiceid from @tmprelease_invoice_mapping); update ROI_RequestCoreDeliveryCharges set Invoice_Balance_Due=Base_Charge where ROI_RequestCoreDeliveryCharges_Seq in (select newinvoiceid from @tmprelease_invoice_mapping);
insert into ROI_RequestCoreChargesFee(ROI_RequestCoreCharges_Seq, Created_By_Seq, Created_Dt, Modified_By_Seq, Modified_Dt, Amount, IsCustomFee, FeeType, Has_Salestax, Salestax_Amount) select @rcChargesId, idx1.Created_By_Seq, idx1.Date, idx1.Modified_By_Seq, idx1.Date, idx1.amount, 1, 'Migration - Debit Adj', 0, 0.00 from @tmpPaymentAdjustments1 idx1 where idx1.draftinvoiceid in (select MAX(ROI_RequestDeliveryCharges_Seq) from @tmpDraftInvoice) and idx1.TransactionType='Adjustment' and idx1.IsDebit='True';
if not exists (select * from @ROI_RequestCoreDeliveryCharges_IDX) begin update rcc set release_cost=release_cost+isnull((select SUM(amount) from @tmpPaymentAdjustments1 idx1 where idx1.draftinvoiceid in (select max(ROI_RequestDeliveryCharges_Seq) from @tmpDraftInvoice) and idx1.TransactionType='Adjustment' and idx1.IsDebit='True'),0.00) from cabinet.dbo.ROI_RequestCoreCharges rcc where rcc.ROI_RequestCoreCharges_Seq = @rcChargesId; end else begin update cabinet.dbo.roi_requestcorecharges set release_cost=0.00, DisplayBillingInfo=0 where roi_requestcorecharges_seq=@rcChargesId; end
set @count = 1; select @max_count=(select MAX(id) from @tmpPaymentAdjustments1); while @count <= @max_count -- start while1 begin if exists (select 1 from @tmpPaymentAdjustments1 where id=@count and TransactionType in ('Payment','Adjustment') and IsDebit='False') BEGIN -- start if1 select @draftinvoiceid=draftinvoiceid, @Amount=amount*-1, @PaymentMode=PaymentMode, @Description=Description, @Date=Date,@TransactionType=TransactionType,@Created_By_Seq=Created_By_Seq, @Modified_By_Seq=Modified_By_Seq from @tmpPaymentAdjustments1 where id=@count and TransactionType in ('Payment','Adjustment') and IsDebit='False'; set @Remaining_Amount = @Amount; if(@TransactionType='Payment') begin insert into ROI_RequestorPayment(ROI_Requestor_Seq, Created_By_Seq, Created_Dt, Modified_By_Seq, Modified_Dt, Record_Version, Amount, PaymentType, Description, UnappliedAmount, PaymentDate, RefundAmount) select @requestor_seq, @Created_By_Seq, @Date, @Modified_By_Seq, @Date, 1, @Amount, @PaymentMode, @Description, @Amount, @Date, 0.00; select @payment_id = SCOPE_IDENTITY(); update @tmpPaymentAdjustments1 set Transaction_Seq=@payment_id where id=@count; -- Add to Jorunal Entry insert into [ROI_JournalEntry] ([ROI_Requestor_Seq], [ROI_FinancialTxnEvent_Seq]) values (@requestor_seq, -3) select @journalentry_id = SCOPE_IDENTITY(); -- Add Journal Detail insert into [ROI_JournalDetail] ([ROI_JournalDetailTemplate_Seq],[ROI_FinancialTxnEvent_Seq],[ROI_FinancialEntityLineItemType_Seq],[ROI_LedgerAccount_Seq],[CreditDebitSideFlag],[DecreaseIncreaseFlag],[ROI_RequestorPayment_Seq],[Amount],[TxnOccurenceTimestamp],[ROI_JournalEntry_Seq]) SELECT [ROI_JournalDetailTemplate_Seq] ,[ROI_FinancialTxnEvent_Seq] ,[ROI_FinancialEntityLineItemType_Seq] ,[ROI_LedgerAccount_Seq] ,[CreditDebitSideFlag] ,[DecreaseIncreaseFlag] ,@payment_id ,@Amount ,@Date ,@journalentry_id FROM [ROI_JournalDetailTemplate] where [ROI_FinancialTxnEvent_Seq] = -3 end else begin insert into ROI_RequestorAdjustment(Created_By_Seq, Created_Dt, Modified_By_Seq, Modified_Dt, Record_Version,Reason, Amount, UnappliedAmount, AdjustmentDate, Note, ROI_Requestor_Seq, AdjustmentType) select @Created_By_Seq,@Date, @Modified_By_Seq, @Date, 1, 'Migration', @Amount, @Amount, @Date, @Description, @requestor_seq, 'Billing'; select @adjustment_id = SCOPE_IDENTITY(); update @tmpPaymentAdjustments1 set Transaction_Seq=@adjustment_id where id=@count; -- Add to Jorunal Entry insert into [ROI_JournalEntry] ([ROI_Requestor_Seq], [ROI_FinancialTxnEvent_Seq]) values (@requestor_seq, -4) select @journalentry_id = SCOPE_IDENTITY(); -- Add Journal Detail insert into [ROI_JournalDetail] ([ROI_JournalDetailTemplate_Seq],[ROI_FinancialTxnEvent_Seq],[ROI_FinancialEntityLineItemType_Seq],[ROI_LedgerAccount_Seq],[CreditDebitSideFlag],[DecreaseIncreaseFlag],[ROI_RequestorAdjustment_Seq],[Amount],[TxnOccurenceTimestamp],[ROI_JournalEntry_Seq]) SELECT [ROI_JournalDetailTemplate_Seq] ,[ROI_FinancialTxnEvent_Seq] ,[ROI_FinancialEntityLineItemType_Seq] ,[ROI_LedgerAccount_Seq] ,[CreditDebitSideFlag] ,[DecreaseIncreaseFlag] ,@adjustment_id ,@Amount ,@Date ,@journalentry_id FROM [ROI_JournalDetailTemplate] where [ROI_FinancialTxnEvent_Seq] = -4 end while (@Remaining_Amount > 0) begin -- start while2 set @newinvoiceid = null; set @newinvoiceid = (select top 1 newinvoiceid from @tmprelease_invoice_mapping where adj_pay_applied=0 order by releaseid); if(@newinvoiceid is null) begin -- start if3 break; end -- end if3 select @invoice_balance_due = Invoice_Balance_Due from ROI_RequestCoreDeliveryCharges where ROI_RequestCoreDeliveryCharges_Seq=@newinvoiceid; if(@invoice_balance_due <= 0) begin -- start if4 break; end -- end if4 if(@invoice_balance_due<=@Remaining_Amount) begin -- start if5 if(@TransactionType='Payment') begin insert into ROI_RequestCoreDeliveryChargestoROI_RequestorPayment(ROI_RequestCoreDeliveryCharges_Seq, ROI_RequestorPayment_Seq, Amount, Created_By_Seq, Created_Dt, Modified_By_Seq, Modified_Dt, Record_Version) select @newinvoiceid, @payment_id, @invoice_balance_due,@Created_By_Seq,@Date,@Modified_By_Seq,@Date,1; select @invoiceToPayment_id = SCOPE_IDENTITY(); -- Add to Jorunal Entry insert into [ROI_JournalEntry] ([ROI_Requestor_Seq], [ROI_FinancialTxnEvent_Seq]) values (@requestor_seq, -14) select @journalentry_id = SCOPE_IDENTITY(); -- Add Journal Detail insert into [ROI_JournalDetail] ([ROI_JournalDetailTemplate_Seq],[ROI_FinancialTxnEvent_Seq],[ROI_FinancialEntityLineItemType_Seq],[ROI_LedgerAccount_Seq],[CreditDebitSideFlag],[DecreaseIncreaseFlag],[ROI_RequestCoreDeliveryChargestoROI_RequestorPayment_Seq],[Amount],[TxnOccurenceTimestamp],[ROI_JournalEntry_Seq]) SELECT [ROI_JournalDetailTemplate_Seq] ,[ROI_FinancialTxnEvent_Seq] ,[ROI_FinancialEntityLineItemType_Seq] ,[ROI_LedgerAccount_Seq] ,[CreditDebitSideFlag] ,[DecreaseIncreaseFlag] ,@invoiceToPayment_id ,@invoice_balance_due ,@Date ,@journalentry_id FROM [ROI_JournalDetailTemplate] where [ROI_FinancialTxnEvent_Seq] = -14 end else begin --calculate sale tax SELECT @total_salesTax_amount=ISNULL(Salestax_Total_Amount, 0),@base_charge=ISNULL(Base_Charge, 0) FROM ROI_RequestCoreDeliveryCharges WHERE ROI_RequestCoreDeliveryCharges_seq=@newinvoiceid set @apply_salesTax_amount= CASE WHEN @base_charge=0 THEN 0 WHEN @total_salesTax_amount=0 THEN 0 ELSE @total_salesTax_amount * @invoice_balance_due / (@base_charge + @total_salesTax_amount) END insert into ROI_RequestCoreDeliveryChargestoROI_RequestorAdjustment(ROI_RequestCoreDeliveryCharges_Seq, ROI_RequestorAdjustment_Seq, Amount, SalesTaxReduction,Created_By_Seq, Created_Dt, Modified_By_Seq, Modified_Dt, Record_Version) select @newinvoiceid, @adjustment_id, @invoice_balance_due, @apply_salesTax_amount,@Created_By_Seq,@Date,@Modified_By_Seq,@Date,1; select @invoiceToAdjustment_id = SCOPE_IDENTITY(); -- Add to Jorunal Entry insert into [ROI_JournalEntry] ([ROI_Requestor_Seq], [ROI_FinancialTxnEvent_Seq]) values (@requestor_seq, -12) select @journalentry_id = SCOPE_IDENTITY(); -- Add Journal Detail insert into [ROI_JournalDetail] ([ROI_JournalDetailTemplate_Seq],[ROI_FinancialTxnEvent_Seq],[ROI_FinancialEntityLineItemType_Seq],[ROI_LedgerAccount_Seq],[CreditDebitSideFlag],[DecreaseIncreaseFlag],[ROI_RequestCoreDeliveryChargestoROI_RequestorAdjustment_Seq],[Amount],[TxnOccurenceTimestamp],[ROI_JournalEntry_Seq]) SELECT [ROI_JournalDetailTemplate_Seq] ,[ROI_FinancialTxnEvent_Seq] ,[ROI_FinancialEntityLineItemType_Seq] ,[ROI_LedgerAccount_Seq] ,[CreditDebitSideFlag] ,[DecreaseIncreaseFlag] ,@invoiceToAdjustment_id ,@invoice_balance_due ,@Date ,@journalentry_id FROM [ROI_JournalDetailTemplate] where [ROI_FinancialTxnEvent_Seq] = -12 and ROI_FinancialEntityLineItemType_Seq = -42 insert into [ROI_JournalDetail] ([ROI_JournalDetailTemplate_Seq],[ROI_FinancialTxnEvent_Seq],[ROI_FinancialEntityLineItemType_Seq],[ROI_LedgerAccount_Seq],[CreditDebitSideFlag],[DecreaseIncreaseFlag],[ROI_RequestCoreDeliveryChargestoROI_RequestorAdjustment_Seq],[Amount],[TxnOccurenceTimestamp],[ROI_JournalEntry_Seq]) SELECT [ROI_JournalDetailTemplate_Seq] ,[ROI_FinancialTxnEvent_Seq] ,[ROI_FinancialEntityLineItemType_Seq] ,[ROI_LedgerAccount_Seq] ,[CreditDebitSideFlag] ,[DecreaseIncreaseFlag] ,@invoiceToAdjustment_id ,@apply_salesTax_amount ,@Date ,@journalentry_id FROM [ROI_JournalDetailTemplate] where [ROI_FinancialTxnEvent_Seq] = -12 and ROI_FinancialEntityLineItemType_Seq = -43 end update ROI_RequestCoreDeliveryCharges set Invoice_Balance_Due = 0 where ROI_RequestCoreDeliveryCharges_Seq=@newinvoiceid; set @Remaining_Amount = @Remaining_Amount - @invoice_balance_due; update @tmprelease_invoice_mapping set adj_pay_applied=1 where newinvoiceid=@newinvoiceid; end -- end if5 else begin -- start else5 if(@TransactionType='Payment') begin insert into ROI_RequestCoreDeliveryChargestoROI_RequestorPayment(ROI_RequestCoreDeliveryCharges_Seq, ROI_RequestorPayment_Seq, Amount, Created_By_Seq, Created_Dt, Modified_By_Seq, Modified_Dt, Record_Version) select @newinvoiceid, @payment_id, @Remaining_Amount,@Created_By_Seq,@Date,@Modified_By_Seq,@Date,1; select @invoiceToPayment_id = SCOPE_IDENTITY(); -- Add to Jorunal Entry insert into [ROI_JournalEntry] ([ROI_Requestor_Seq], [ROI_FinancialTxnEvent_Seq]) values (@requestor_seq, -14) select @journalentry_id = SCOPE_IDENTITY(); -- Add Journal Detail insert into [ROI_JournalDetail] ([ROI_JournalDetailTemplate_Seq],[ROI_FinancialTxnEvent_Seq],[ROI_FinancialEntityLineItemType_Seq],[ROI_LedgerAccount_Seq],[CreditDebitSideFlag],[DecreaseIncreaseFlag],[ROI_RequestCoreDeliveryChargestoROI_RequestorPayment_Seq],[Amount],[TxnOccurenceTimestamp],[ROI_JournalEntry_Seq]) SELECT [ROI_JournalDetailTemplate_Seq] ,[ROI_FinancialTxnEvent_Seq] ,[ROI_FinancialEntityLineItemType_Seq] ,[ROI_LedgerAccount_Seq] ,[CreditDebitSideFlag] ,[DecreaseIncreaseFlag] ,@invoiceToPayment_id ,@Remaining_Amount ,@Date ,@journalentry_id FROM [ROI_JournalDetailTemplate] where [ROI_FinancialTxnEvent_Seq] = -14 end else begin --calculate sale tax SELECT @total_salesTax_amount=ISNULL(Salestax_Total_Amount, 0),@base_charge=ISNULL(Base_Charge, 0) FROM ROI_RequestCoreDeliveryCharges WHERE ROI_RequestCoreDeliveryCharges_seq=@newinvoiceid set @apply_salesTax_amount= CASE WHEN @base_charge=0 THEN 0 WHEN @total_salesTax_amount=0 THEN 0 ELSE @total_salesTax_amount * @invoice_balance_due / (@base_charge + @total_salesTax_amount) END
insert into ROI_RequestCoreDeliveryChargestoROI_RequestorAdjustment(ROI_RequestCoreDeliveryCharges_Seq, ROI_RequestorAdjustment_Seq, Amount, SalesTaxReduction, Created_By_Seq, Created_Dt, Modified_By_Seq, Modified_Dt, Record_Version) select @newinvoiceid, @adjustment_id, @Remaining_Amount,@apply_salesTax_amount, @Created_By_Seq,@Date,@Modified_By_Seq,@Date,1; select @invoiceToAdjustment_id = SCOPE_IDENTITY(); -- Add to Jorunal Entry insert into [ROI_JournalEntry] ([ROI_Requestor_Seq], [ROI_FinancialTxnEvent_Seq]) values (@requestor_seq, -12) select @journalentry_id = SCOPE_IDENTITY(); -- Add Journal Detail insert into [ROI_JournalDetail] ([ROI_JournalDetailTemplate_Seq],[ROI_FinancialTxnEvent_Seq],[ROI_FinancialEntityLineItemType_Seq],[ROI_LedgerAccount_Seq],[CreditDebitSideFlag],[DecreaseIncreaseFlag],[ROI_RequestCoreDeliveryChargestoROI_RequestorAdjustment_Seq],[Amount],[TxnOccurenceTimestamp],[ROI_JournalEntry_Seq]) SELECT [ROI_JournalDetailTemplate_Seq] ,[ROI_FinancialTxnEvent_Seq] ,[ROI_FinancialEntityLineItemType_Seq] ,[ROI_LedgerAccount_Seq] ,[CreditDebitSideFlag] ,[DecreaseIncreaseFlag] ,@invoiceToAdjustment_id ,@invoice_balance_due ,@Date ,@journalentry_id FROM [ROI_JournalDetailTemplate] where [ROI_FinancialTxnEvent_Seq] = -12 and ROI_FinancialEntityLineItemType_Seq = -42 insert into [ROI_JournalDetail] ([ROI_JournalDetailTemplate_Seq],[ROI_FinancialTxnEvent_Seq],[ROI_FinancialEntityLineItemType_Seq],[ROI_LedgerAccount_Seq],[CreditDebitSideFlag],[DecreaseIncreaseFlag],[ROI_RequestCoreDeliveryChargestoROI_RequestorAdjustment_Seq],[Amount],[TxnOccurenceTimestamp],[ROI_JournalEntry_Seq]) SELECT [ROI_JournalDetailTemplate_Seq] ,[ROI_FinancialTxnEvent_Seq] ,[ROI_FinancialEntityLineItemType_Seq] ,[ROI_LedgerAccount_Seq] ,[CreditDebitSideFlag] ,[DecreaseIncreaseFlag] ,@invoiceToAdjustment_id ,@apply_salesTax_amount ,@Date ,@journalentry_id FROM [ROI_JournalDetailTemplate] where [ROI_FinancialTxnEvent_Seq] = -12 and ROI_FinancialEntityLineItemType_Seq = -43 end update ROI_RequestCoreDeliveryCharges set Invoice_Balance_Due = (Invoice_Balance_Due-@Remaining_Amount) where ROI_RequestCoreDeliveryCharges_Seq=@newinvoiceid; set @Remaining_Amount = 0; end -- end else5 end -- end while2 if(@TransactionType='Payment') begin update ROI_RequestorPayment set UnappliedAmount=@Remaining_Amount where ROI_RequestorPayment_Seq=@payment_id; end else begin update ROI_RequestorAdjustment set UnappliedAmount=@Remaining_Amount where ROI_RequestorAdjustment_Seq=@adjustment_id; end END -- end if1 set @count = @count+1; end -- end while1
insert into cabinet.dbo.ROI_ConversionMapping_RequestorPayment (ROI_RequestorPayment_Seq, ROI_RequestCore_Seq) select Transaction_Seq, @requestId from @tmpPaymentAdjustments1 where TransactionType='Payment' and Transaction_Seq is not null;
insert into cabinet.dbo.ROI_ConversionMapping_RequestorAdjustment (ROI_RequestorAdjustment_Seq, ROI_RequestCore_Seq) select Transaction_Seq, @requestId from @tmpPaymentAdjustments1 where TransactionType='Adjustment' and IsDebit='False' and Transaction_Seq is not null;

insert into @tmpPrebill select rdc.ROI_RequestDeliveryCharges_Seq from cabinet.dbo.ROI_RequestDeliveryCharges rdc join ROI_RequestDelivery rd on rdc.ROI_RequestDelivery_Seq=rd.ROI_RequestDelivery_Seq where rdc.isInvoiced=1 and rd.ROI_RequestMain_Seq=@requestId and rdc.RequestDeliveryChargesXML.value('(/release-item[@type="billing-doc"]/attribute[@name="type"]/@value)[1]','varchar(max)') = 'PreBill'
if exists (select * from @tmpPrebill) begin insert into cabinet.dbo.ROI_RequestCoreDeliveryCharges (ROI_RequestCore_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, Previously_Released_Cost, Release_Date, Total_Pages, Total_Pages_Released, Salestax_Total_Amount, Salestax_Percentage_BillingLoc, Letter_Template_Name, Request_Status, Request_Date, LetterTemplate_FileId, Type, Invoice_Prebill_Date, Invoice_Due_Date, Resend_Date, Output_Method, Queue_Password, Invoice_Salestax, Base_Charge, Balance_Due, FACILITY_CODE, FACILITY_NAME, Invoice_Balance_Due, Is_Released, Billing_Type, Apply_SalesTax, Notes, Invoice_Due_Days, Overwrite_Due_Date, Unbillable, PreBill_Status, Unbillable_Amount) output inserted.ROI_RequestCoreDeliveryCharges_Seq, inserted.Created_By_Seq into @tmpNewPrebill select @requestId, irdc.Created_Dt, prebill.ROI_RequestDeliveryCharges_Seq, irdc.Modified_Dt, irdc.Modified_By_Seq, irdc.Record_Version, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="previously-released-cost"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Previously_Released_Cost, NULLIF(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="release-date"]/@value)[1]','smalldatetime'),'') as Release_Date, ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="total-pages"]/@value)[1]','int'),0) as Total_Pages, ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="total-pages-released"]/@value)[1]','int'),0) as Total_Pages_Released, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="salestax-total-amount"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Salestax_Total_Amount, ISNULL(p.value('(./attribute[@name="sales-tax-percentage"]/@value)[1]','decimal(18,2)'),0.00) as Salestax_Percentage_BillingLoc, p.value('(./attribute[@name="lettertemplate-name"]/@value)[1]','varchar(50)') as Letter_Template_Name, ISNULL(p.value('(./attribute[@name="request-status"]/@value)[1]','varchar(50)'),'') as Request_Status, p.value('(./attribute[@name="request-dt"]/@value)[1]','smalldatetime') as Request_Date, ISNULL(p.value('(./attribute[@name="lettertemplate-fileid"]/@value)[1]','int'),1) as LetterTemplate_FileId, ISNULL(p.value('(./attribute[@name="type"]/@value)[1]','varchar(10)'),'') as Type, ISNULL(p.value('(./attribute[@name="invoice-prebill-date"]/@value)[1]','smalldatetime'),p.value('(./attribute[@name="request-dt"]/@value)[1]','smalldatetime')) as Invoice_Prebill_Date, dateadd(day, @defaultInvoiceDueDays, irdc.Created_Dt) as Invoice_Due_Date, ISNULL(p.value('(./attribute[@name="resend-dt"]/@value)[1]','smalldatetime'),p.value('(./attribute[@name="request-dt"]/@value)[1]','smalldatetime')) as Resend_Date, ISNULL(p.value('(./attribute[@name="output-method"]/@value)[1]','varchar(50)'),'') as Output_Method, p.value('(./attribute[@name="queue-password"]/@value)[1]','varchar(50)') as Queue_Password, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="invoice-info"]/attribute[@name="inv-sales-tax"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Invoice_Salestax, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="release-cost"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Base_Charge, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="balance-due"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Balance_Due, @defaultFacilityCode as FACILITY_CODE, @defaultFacilityName as FACILITY_NAME, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="invoice-info"]/attribute[@name="inv-balance-due"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Invoice_Balance_Due, irdc.isReleased, p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="FeeCharge"]/attribute[@name="billing-type"]/@value)[1]','varchar(50)') as Billing_Type, 0 as Apply_SalesTax, (select stuff( (select '~'+ c.value('./@value[1]','varchar(max)') from [RequestDeliveryChargesXML].nodes('/release-item[@type="billing-doc"]/release-item[@type="notes"]/release-item/attribute[@name="description"]') as t(c) FOR XML PATH('')),1,1,'')) as Notes, @defaultInvoiceDueDays as Invoice_Due_Days, 0 as Overwrite_Due_Date, 0 as Unbillable, 'Active' as PreBill_Status, 0.00 as Unbillable_Amount from ROI_RequestDeliveryCharges irdc join @tmpPrebill prebill on irdc.ROI_RequestDeliveryCharges_Seq=prebill.ROI_RequestDeliveryCharges_Seq cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-doc"]') as p(p);
INSERT into @tmpPREBILL_RequestCoreDeliveryChargesInvoicePatients select (select ROI_RequestCoreDeliveryCharges_Seq from @tmpNewPrebill where ROI_RequestDeliveryCharges_Seq = prebill.ROI_RequestDeliveryCharges_Seq), t.c.value('(attribute[@name="patientmrn"]/@value)[1]','varchar(20)') as mrn, t.c.value('(attribute[@name="facility"]/@value)[1]','varchar(10)') as facility, t.c.value('(attribute[@name="patientname"]/@value)[1]','varchar(40)') as patientName from ROI_RequestDeliveryCharges drdc join @tmpPrebill prebill on drdc.ROI_RequestDeliveryCharges_Seq=prebill.ROI_RequestDeliveryCharges_Seq cross apply [RequestDeliveryChargesXML].nodes('/release-item[@type="billing-doc"]/release-item[@type="requestItem"]/release-item') t(c);
INSERT INTO ROI_RequestCoreDeliveryChargesInvoicePatients ( ROI_RequestCoreDeliveryCharges_Seq ,ROI_SupplementalPatientsCore_Seq , ROI_Patients_Seq ) select a.ROI_RequestCoreDeliveryCharges_Seq, null as ROI_SupplementalPatientsCore_Seq, b.ROI_Patients_Seq as ROI_Patients_Seq from @tmpPREBILL_RequestCoreDeliveryChargesInvoicePatients a join ROI_Patients b on (a.patientName = b.Name and a.MRN = b.MRN and a.Facility = b.Facility) where b.ROI_Patients_seq in (select ROI_Patients_seq from ROI_RequestCoretoROI_Patients where ROI_RequestCore_Seq = @requestId) Union select a.ROI_RequestCoreDeliveryCharges_Seq, b.ROI_SupplementalPatientsCore_Seq, NULL as ROI_Patients_Seq from @tmpPREBILL_RequestCoreDeliveryChargesInvoicePatients a join ROI_SupplementalPatientsCore b on (a.patientName = (b.lastName + ', ' + b.firstName) and a.MRN = b.MRN and a.Facility = b.Facility) where b.ROI_SupplementalPatientsCore_Seq in (select ROI_SupplementalPatientsCore_Seq from ROI_RequestCoretoROI_SupplementalPatientsCore where ROI_RequestCore_Seq = @requestId);
insert into cabinet.dbo.ROI_RequestCoreDeliveryChargesDocument (ROI_RequestCoreDeliveryCharges_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, Amount, Copies, TotalPages, Pages, BillingTierName, BillingTierId, ReleaseCount, isElectronic, RemoveBasecharge, Has_Salestax, Salestax_Amount) select (select ROI_RequestCoreDeliveryCharges_Seq from @tmpNewPrebill where ROI_RequestDeliveryCharges_Seq = prebill.ROI_RequestDeliveryCharges_Seq), drdc.Created_Dt, drdc.Created_By_Seq, drdc.Modified_Dt, drdc.Modified_By_Seq, drdc.Record_Version, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="amount"]/@value)[1]','varchar(20)'), 0.00), '$',''),')',''), '(', '-'),',','') as Amount, ISNULL(p.value('(./attribute[@name="copies"]/@value)[1]','varchar(20)'),0) as Copies, ISNULL(p.value('(./attribute[@name="total-pages"]/@value)[1]','varchar(20)'),0) as TotalPages, ISNULL(p.value('(./attribute[@name="pages"]/@value)[1]','varchar(20)'),0) as Pages, ISNULL(p.value('(./attribute[@name="billingtier-name"]/@value)[1]','varchar(256)'),'') as BillingTierName, ISNULL(p.value('(./attribute[@name="billingtier-id"]/@value)[1]','varchar(20)'),0) as BillingTierId, ISNULL(p.value('(./attribute[@name="release-count"]/@value)[1]','varchar(20)'),0) as ReleaseCount, case p.value('(./attribute[@name="is-electronic"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as IsElectronic, case p.value('(./attribute[@name="remove-basecharge"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as RemoveBaseCharge, case p.value('(./attribute[@name="has-salestax"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as Has_Salestax, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="salestax-amount"]/@value)[1]','varchar(max)'),0.00), '$',''), ')', ''), '(', '-'),',','') as SalesTax_Amount from ROI_RequestDeliveryCharges drdc join @tmpPrebill prebill on drdc.ROI_RequestDeliveryCharges_Seq=prebill.ROI_RequestDeliveryCharges_Seq cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-doc"]/release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="DocumentCharge"]/release-item') as p(p);
insert into cabinet.dbo.ROI_RequestCoreDeliveryChargesFee (ROI_RequestCoreDeliveryCharges_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, Amount, IsCustomFee, FeeType, Has_Salestax, Salestax_Amount) select (select ROI_RequestCoreDeliveryCharges_Seq from @tmpNewPrebill where ROI_RequestDeliveryCharges_Seq = prebill.ROI_RequestDeliveryCharges_Seq), drdc.Created_Dt, drdc.Created_By_Seq, drdc.Modified_Dt, drdc.Modified_By_Seq, drdc.Record_Version, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="amount"]/@value)[1]','varchar(max)'), 0.00), '$',''),')',''), '(', '-'),',','') as Amount, case p.value('(./attribute[@name="is-custom-fee"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as IsCustomFee, p.value('(./attribute[@name="feetype"]/@value)[1]','varchar(50)') as FeeType, case p.value('(./attribute[@name="has-salestax"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as Has_Salestax, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="salestax-amount"]/@value)[1]','varchar(max)'),0.00), '$',''), ')', ''), '(', '-'),',','') as SalesTax_Amount from ROI_RequestDeliveryCharges drdc join @tmpPrebill prebill on drdc.ROI_RequestDeliveryCharges_Seq=prebill.ROI_RequestDeliveryCharges_Seq cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-doc"]/release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="FeeCharge"]/release-item') as p(p);
insert into cabinet.dbo.ROI_RequestCoreDeliveryChargesShipping (ROI_RequestCoreDeliveryCharges_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, ShippingCharge, AddressType, Address1, Address2, Address3, City, State, PostalCode, ShippingUrl, ShippingWeight, TrackingNumber, WillReleaseShipped, ShippingMethod, OutputMethod, ShippingMethodId) select (select ROI_RequestCoreDeliveryCharges_Seq from @tmpNewPrebill where ROI_RequestDeliveryCharges_Seq = prebill.ROI_RequestDeliveryCharges_Seq), drdc.Created_Dt, drdc.Created_By_Seq, drdc.Modified_Dt, drdc.Modified_By_Seq, drdc.Record_Version, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(../release-item[@type="charges"]/release-item[@type="shipping-charge"]/attribute[@name="shipping-charge"]/@value)[1]','varchar(max)'),0.00), '$',''), ')', ''), '(', '-'),',','') as ShippingCharge, p.value('(./attribute[@name="address-type"]/@value)[1]','varchar(20)') as AddressType, p.value('(./attribute[@name="address1"]/@value)[1]','varchar(256)') as Address1, p.value('(./attribute[@name="address2"]/@value)[1]','varchar(256)') as Address2, p.value('(./attribute[@name="address3"]/@value)[1]','varchar(256)') as Address3, p.value('(./attribute[@name="city"]/@value)[1]','varchar(50)') as City, p.value('(./attribute[@name="state"]/@value)[1]','varchar(20)') as State, p.value('(./attribute[@name="postalcode"]/@value)[1]','varchar(20)') as PostalCode, p.value('(./attribute[@name="shipping-url"]/@value)[1]','varchar(50)') as ShippingUrl, ISNULL(p.value('(./attribute[@name="shipping-weight"]/@value)[1]','varchar(max)'),0) as ShippingWeight, p.value('(./attribute[@name="tracking-number"]/@value)[1]','varchar(35)') as TrackingNumber, case p.value('(./attribute[@name="will-release-shipped"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as WillReleaseShipped, p.value('(./attribute[@name="shipping-method"]/@value)[1]','varchar(35)') as ShippingMethod, p.value('(./attribute[@name="output-method"]/@value)[1]','varchar(35)') as OutputMethod, p.value('(./attribute[@name="shipping-method-id"]/@value)[1]','bigint') as ShippingMethodId from ROI_RequestDeliveryCharges drdc join @tmpPrebill prebill on drdc.ROI_RequestDeliveryCharges_Seq=prebill.ROI_RequestDeliveryCharges_Seq cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-doc"]/release-item[@type="billing-info"]/release-item[@type="shipping-info"]') as p(p);
end

insert into @tmpRelease select ROI_RequestDelivery_Seq, p.value('(./@is-released)[1]','varchar(10)') as isReleased, Created_Dt as releaseDate from ROI_RequestDelivery cross apply RequestDeliveryXML.nodes('/release') as p(p) where ROI_RequestMain_Seq=@requestId
insert into @tmpInvoice select * from ( select ROI_RequestDelivery_Seq, ROI_RequestDeliveryCharges_Seq as invoiceId, p.value('(./attribute[@name="type"]/@value)[1]','varchar(10)') as Type from ROI_RequestDeliveryCharges cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-doc"]') as p(p) where isInvoiced=1 and ROI_RequestDelivery_Seq in (select ROI_RequestDelivery_Seq from @tmpRelease) ) as X where type= 'Invoice'
insert into @tmpInvoiceMigrated select ROI_RequestDelivery_Seq, ROI_RequestDeliveryCharges_Seq from ROI_RequestDeliveryCharges where isInvoiced=1 and ROI_RequestDelivery_Seq in (select ROI_RequestDelivery_Seq from @tmpRelease) and RequestDeliveryChargesXML.value('(/release-item/attribute[@name="type"]/@value)[1]','varchar(max)')='Invoice'
insert into @tmpDraftInvoice select ROI_RequestDelivery_Seq, max(ROI_RequestDeliveryCharges_Seq) as draftInvoiceId from ROI_RequestDeliveryCharges where isInvoiced=0 and ROI_RequestDelivery_Seq in (select ROI_RequestDelivery_Seq from @tmpRelease) group by ROI_RequestDelivery_Seq
insert into @tmprelease_invoice_mapping(releaseid, isReleased, releaseDate, invoiceid, draftinvoiceid, Type) select r.ROI_RequestDelivery_Seq , r.isReleased, r.releaseDate, i.ROI_RequestDeliveryCharges_Seq as invoiceid, di.ROI_RequestDeliveryCharges_Seq as draftinvoiceid, i.Type from @tmpRelease r left join @tmpInvoice i on r.ROI_RequestDelivery_Seq = i.ROI_RequestDelivery_Seq left join @tmpDraftInvoice di on r.ROI_RequestDelivery_Seq = di.ROI_RequestDelivery_Seq where (r.isReleased <> 'False' or i.ROI_RequestDeliveryCharges_Seq is not null) and (r.isReleased <> 'False')
insert into cabinet.dbo.ROI_RequestCoreDeliveryCharges (ROI_RequestCore_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, Previously_Released_Cost, Release_Date, Total_Pages, Total_Pages_Released, Salestax_Total_Amount, Salestax_Percentage_BillingLoc, Letter_Template_Name, Request_Status, Request_Date, LetterTemplate_FileId, Type, Invoice_Prebill_Date, Invoice_Due_Date, Resend_Date, Output_Method, Queue_Password, Invoice_Salestax, Base_Charge, Balance_Due, FACILITY_CODE, FACILITY_NAME, Invoice_Balance_Due, Is_Released, Billing_Type, Apply_SalesTax, Notes, Invoice_Due_Days, Overwrite_Due_Date, Unbillable, PreBill_Status, Unbillable_Amount) output inserted.ROI_RequestCoreDeliveryCharges_Seq, inserted.Created_By_Seq, inserted.ROI_RequestCore_Seq into @ROI_RequestCoreDeliveryCharges_IDX select @requestId, irdc.Created_Dt, rim.invoiceid, irdc.Modified_Dt, irdc.Modified_By_Seq, irdc.Record_Version, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="previously-released-cost"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Previously_Released_Cost, NULLIF(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="release-date"]/@value)[1]','smalldatetime'),'') as Release_Date, ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="total-pages"]/@value)[1]','int'),0) as Total_Pages, ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="total-pages-released"]/@value)[1]','int'),0) as Total_Pages_Released, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="salestax-total-amount"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Salestax_Total_Amount, ISNULL(p.value('(./attribute[@name="sales-tax-percentage"]/@value)[1]','decimal(18,2)'),0.00) as Salestax_Percentage_BillingLoc, p.value('(./attribute[@name="lettertemplate-name"]/@value)[1]','varchar(50)') as Letter_Template_Name, ISNULL(p.value('(./attribute[@name="request-status"]/@value)[1]','varchar(50)'),'') as Request_Status, p.value('(./attribute[@name="request-dt"]/@value)[1]','smalldatetime') as Request_Date, ISNULL(p.value('(./attribute[@name="lettertemplate-fileid"]/@value)[1]','int'),1) as LetterTemplate_FileId, ISNULL(p.value('(./attribute[@name="type"]/@value)[1]','varchar(10)'),'') as Type, ISNULL(p.value('(./attribute[@name="invoice-prebill-date"]/@value)[1]','smalldatetime'),p.value('(./attribute[@name="request-dt"]/@value)[1]','smalldatetime')) as Invoice_Prebill_Date, ISNULL(p.value('(./attribute[@name="invoice-due-date"]/@value)[1]','smalldatetime'),p.value('(./attribute[@name="request-dt"]/@value)[1]','smalldatetime')) as Invoice_Due_Date, ISNULL(p.value('(./attribute[@name="resend-dt"]/@value)[1]','smalldatetime'),p.value('(./attribute[@name="request-dt"]/@value)[1]','smalldatetime')) as Resend_Date, ISNULL(p.value('(./attribute[@name="output-method"]/@value)[1]','varchar(50)'),'') as Output_Method, p.value('(./attribute[@name="queue-password"]/@value)[1]','varchar(50)') as Queue_Password, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="invoice-info"]/attribute[@name="inv-sales-tax"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Invoice_Salestax, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="invoice-info"]/attribute[@name="base-charge"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Base_Charge, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="balance-due"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Balance_Due, ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="invoice-info"]/attribute[@name="inv-billing-loc-code"]/@value)[1]','varchar(20)'),'') as FACILITY_CODE, ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="invoice-info"]/attribute[@name="inv-billing-loc-name"]/@value)[1]','varchar(20)'),'') as FACILITY_NAME, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="invoice-info"]/attribute[@name="inv-balance-due"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Invoice_Balance_Due, irdc.isReleased, p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="FeeCharge"]/attribute[@name="billing-type"]/@value)[1]','varchar(50)') as Billing_Type, @applySalesTax as Apply_SalesTax, (select stuff( (select '~'+ c.value('./@value[1]','varchar(max)') from [RequestDeliveryChargesXML].nodes('/release-item[@type="billing-doc"]/release-item[@type="notes"]/release-item/attribute[@name="description"]') as t(c) FOR XML PATH('')),1,1,'')) as Notes, 0 as Invoice_Due_Days, ISNULL(p.value('(./attribute[@name="overwrite-due-date"]/@value)[1]','varchar(50)'),'') as Overwrite_Due_Date, 0 as Unbillable, 'Active' as PreBill_Status, 0.00 as Unbillable_Amount from ROI_RequestDeliveryCharges irdc join @tmprelease_invoice_mapping rim on irdc.ROI_RequestDeliveryCharges_Seq = rim.invoiceid cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-doc"]') as p(p)
update ROI_RequestCoreCharges set Release_Cost = 0.00,DisplayBillingInfo = 0 where ROI_RequestCore_Seq = @requestId update idx1 set newinvoiceid=idx2.ROI_RequestCoreDeliveryCharges_Seq from @tmprelease_invoice_mapping idx1 join @ROI_RequestCoreDeliveryCharges_IDX idx2 on idx1.invoiceid = idx2.releaseid; update idx1 set Is_Released=idx3.isReleased from ROI_RequestCoreDeliveryCharges idx1 join @tmprelease_invoice_mapping idx2 on idx1.ROI_RequestCoreDeliveryCharges_Seq=idx2.newinvoiceid join ROI_RequestDeliveryCharges idx3 on idx2.draftinvoiceid=idx3.ROI_RequestDeliveryCharges_Seq; update ROI_RequestCoreDeliveryCharges set Invoice_Due_Days=DATEDIFF(day,Request_Date,Invoice_Due_Date) where ROI_RequestCoreDeliveryCharges_Seq in (select newinvoiceid from @tmprelease_invoice_mapping) update ROI_RequestCoreDeliveryCharges set PreBill_Status='InActive' where ROI_RequestCoreDeliveryCharges_Seq in (select newinvoiceid from @tmprelease_invoice_mapping where releaseid in (select releaseid from @tmprelease_invoice_mapping where Type ='Invoice'));
--update idx1 set Base_Charge=ISNULL((select Base_Charge from ROI_RequestCoreDeliveryCharges where ROI_RequestCoreDeliveryCharges_Seq in (select top 1 newinvoiceid from @tmprelease_invoice_mapping where releaseid in (select releaseid from @tmprelease_invoice_mapping where newinvoiceid=idx1.ROI_RequestCoreDeliveryCharges_Seq))), 0) from ROI_RequestCoreDeliveryCharges idx1 where Type='Invoice';
insert into cabinet.dbo.ROI_RequestCoreDeliveryChargesDocument (ROI_RequestCoreDeliveryCharges_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, Amount, Copies, TotalPages, Pages, BillingTierName, BillingTierId, ReleaseCount, isElectronic, RemoveBasecharge, Has_Salestax, Salestax_Amount) select (select ROI_RequestCoreDeliveryCharges_Seq from @ROI_RequestCoreDeliveryCharges_IDX where releaseid = rim.invoiceid), drdc.Created_Dt, drdc.Created_By_Seq, drdc.Modified_Dt, drdc.Modified_By_Seq, drdc.Record_Version, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="amount"]/@value)[1]','varchar(20)'), 0.00), '$',''),')',''), '(', '-'),',','') as Amount, ISNULL(p.value('(./attribute[@name="copies"]/@value)[1]','varchar(20)'),0) as Copies, ISNULL(p.value('(./attribute[@name="total-pages"]/@value)[1]','varchar(20)'),0) as TotalPages, ISNULL(p.value('(./attribute[@name="pages"]/@value)[1]','varchar(20)'),0) as Pages, ISNULL(p.value('(./attribute[@name="billingtier-name"]/@value)[1]','varchar(256)'),'') as BillingTierName, ISNULL(p.value('(./attribute[@name="billingtier-id"]/@value)[1]','varchar(20)'),0) as BillingTierId, ISNULL(p.value('(./attribute[@name="release-count"]/@value)[1]','varchar(20)'),0) as ReleaseCount, case p.value('(./attribute[@name="is-electronic"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as IsElectronic, case p.value('(./attribute[@name="remove-basecharge"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as RemoveBaseCharge, case p.value('(./attribute[@name="has-salestax"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as Has_Salestax, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="salestax-amount"]/@value)[1]','varchar(max)'),0.00), '$',''), ')', ''), '(', '-'),',','') as SalesTax_Amount from ROI_RequestDeliveryCharges drdc join @tmprelease_invoice_mapping rim on drdc.ROI_RequestDeliveryCharges_Seq = rim.invoiceid cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-doc"]/release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="DocumentCharge"]/release-item') as p(p);
insert into cabinet.dbo.ROI_RequestCoreDeliveryChargesFee (ROI_RequestCoreDeliveryCharges_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, Amount, IsCustomFee, FeeType, Has_Salestax, Salestax_Amount) select (select ROI_RequestCoreDeliveryCharges_Seq from @ROI_RequestCoreDeliveryCharges_IDX where releaseid = rim.invoiceid), drdc.Created_Dt, drdc.Created_By_Seq, drdc.Modified_Dt, drdc.Modified_By_Seq, drdc.Record_Version, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="amount"]/@value)[1]','varchar(max)'), 0.00), '$',''),')',''), '(', '-'),',','') as Amount, case p.value('(./attribute[@name="is-custom-fee"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as IsCustomFee, p.value('(./attribute[@name="feetype"]/@value)[1]','varchar(50)') as FeeType, case p.value('(./attribute[@name="has-salestax"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as Has_Salestax, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="salestax-amount"]/@value)[1]','varchar(max)'),0.00), '$',''), ')', ''), '(', '-'),',','') as SalesTax_Amount from ROI_RequestDeliveryCharges drdc join @tmprelease_invoice_mapping rim on drdc.ROI_RequestDeliveryCharges_Seq = rim.invoiceid cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-doc"]/release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="FeeCharge"]/release-item') as p(p);
insert into cabinet.dbo.ROI_RequestCoreDeliveryChargesShipping (ROI_RequestCoreDeliveryCharges_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, ShippingCharge, AddressType, Address1, Address2, Address3, City, State, PostalCode, ShippingUrl, ShippingWeight, TrackingNumber, WillReleaseShipped, ShippingMethod, OutputMethod, ShippingMethodId) select (select ROI_RequestCoreDeliveryCharges_Seq from @ROI_RequestCoreDeliveryCharges_IDX where releaseid = rim.invoiceid), drdc.Created_Dt, drdc.Created_By_Seq, drdc.Modified_Dt, drdc.Modified_By_Seq, drdc.Record_Version, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(../release-item[@type="charges"]/release-item[@type="shipping-charge"]/attribute[@name="shipping-charge"]/@value)[1]','varchar(max)'),0.00), '$',''), ')', ''), '(', '-'),',','') as ShippingCharge, p.value('(./attribute[@name="address-type"]/@value)[1]','varchar(20)') as AddressType, p.value('(./attribute[@name="address1"]/@value)[1]','varchar(256)') as Address1, p.value('(./attribute[@name="address2"]/@value)[1]','varchar(256)') as Address2, p.value('(./attribute[@name="address3"]/@value)[1]','varchar(256)') as Address3, p.value('(./attribute[@name="city"]/@value)[1]','varchar(50)') as City, p.value('(./attribute[@name="state"]/@value)[1]','varchar(20)') as State, p.value('(./attribute[@name="postalcode"]/@value)[1]','varchar(20)') as PostalCode, p.value('(./attribute[@name="shipping-url"]/@value)[1]','varchar(50)') as ShippingUrl, ISNULL(p.value('(./attribute[@name="shipping-weight"]/@value)[1]','varchar(max)'),0) as ShippingWeight, p.value('(./attribute[@name="tracking-number"]/@value)[1]','varchar(35)') as TrackingNumber, case p.value('(./attribute[@name="will-release-shipped"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as WillReleaseShipped, p.value('(./attribute[@name="shipping-method"]/@value)[1]','varchar(35)') as ShippingMethod, p.value('(./attribute[@name="output-method"]/@value)[1]','varchar(35)') as OutputMethod, 