insert into @tmpROI_RequestCoreDeliveryChargesInvoicePatients select (select top 1 ROI_RequestCoreDeliveryCharges_Seq from @ROI_RequestCoreDeliveryCharges_IDX where invoiceid = rim.invoiceid), t.c.value('(attribute[@name="patientmrn"]/@value)[1]','varchar(20)') as mrn, t.c.value('(attribute[@name="facility"]/@value)[1]','varchar(10)') as facility, t.c.value('(attribute[@name="patientname"]/@value)[1]','varchar(40)') as patientName from ROI_RequestDeliveryCharges irdc join @tmprelease_invoice_mapping rim on irdc.ROI_RequestDeliveryCharges_Seq = rim.invoiceid cross apply [RequestDeliveryChargesXML].nodes('/release-item[@type="billing-doc"]/release-item[@type="requestItem"]/release-item') t(c)
