mpInvoiceMigrated idx2 on idx1.releaseid=idx2.ROI_RequestDelivery_Seq join ROI_RequestDeliveryCharges rdc on rdc.ROI_RequestDeliveryCharges_Seq = idx2.ROI_RequestDeliveryCharges_Seq cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-doc"]') as p(p)
-- CR 386696 - Start if not exists (select * from ROI_RequestCoreDeliveryCharges where ROI_RequestCore_Seq = @requestId) begin insert into @tmpUnappliedPaymentAdjustments1(draftinvoiceid, Amount, PaymentMode, Description, Date, TransactionType, IsDebit, Created_By_Seq, Modified_By_Seq) select ROI_RequestDeliveryCharges_Seq, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="amount"]/@value)[1]','varchar(max)'), 0.00), '$',''),')',''), '(', '-'),',','') as Amount, p.value('(./attribute[@name="payment-mode"]/@value)[1]','varchar(50)') as PaymentMode, p.value('(./attribute[@name="description"]/@value)[1]','varchar(256)') as Description, p.value('(./attribute[@name="date"]/@value)[1]','datetime') as Date, p.value('(./attribute[@name="transaction-type"]/@value)[1]','varchar(50)') as TransactionType, p.value('(./attribute[@name="is-debit"]/@value)[1]','varchar(10)') as IsDebit, Created_By_Seq, Modified_By_Seq from ROI_RequestDeliveryCharges cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-doc"]/release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="request-transaction"]/release-item') as p(p) where ROI_RequestDeliveryCharges_Seq in (select ROI_RequestDeliveryCharges_Seq from @tmpInvoice);
