late_Seq],[ROI_FinancialTxnEvent_Seq],[ROI_FinancialEntityLineItemType_Seq],[ROI_LedgerAccount_Seq],[CreditDebitSideFlag],[DecreaseIncreaseFlag],[ROI_RequestCoreDeliveryChargestoROI_RequestorAdjustment_Seq],[Amount],[TxnOccurenceTimestamp],[ROI_JournalEntry_Seq]) SELECT [ROI_JournalDetailTemplate_Seq] ,[ROI_FinancialTxnEvent_Seq] ,[ROI_FinancialEntityLineItemType_Seq] ,[ROI_LedgerAccount_Seq] ,[CreditDebitSideFlag] ,[DecreaseIncreaseFlag] ,@invoiceToAdjustment_id ,@invoice_balance_due ,@Date ,@journalentry_id FROM [ROI_JournalDetailTemplate] where [ROI_FinancialTxnEvent_Seq] = -12 and ROI_FinancialEntityLineItemType_Seq = -42 insert into [ROI_JournalDetail] ([ROI_JournalDetailTemplate_Seq],[ROI_FinancialTxnEvent_Seq],[ROI_FinancialEntityLineItemType_Seq],[ROI_LedgerAccount_Seq],[CreditDebitSideFlag],[DecreaseIncreaseFlag],[ROI_RequestCoreDeliveryChargestoROI_RequestorAdjustment_Seq],[Amount],[TxnOccurenceTimestamp],[ROI_JournalEntry_Seq]) SELECT [ROI_JournalDetailTemplate_Seq] ,[ROI_FinancialTxnEvent_Seq] ,[ROI_FinancialEntityLineItemType_Seq] ,[ROI_LedgerAccount_Seq] ,[CreditDebitSideFlag] ,[DecreaseIncreaseFlag] ,@invoiceToAdjustment_id -- Wheaton Escalation Change - Start ,ISNULL(@apply_salesTax_amount,0.0) -- Wheaton Escalation Change - End ,@Date ,@journalentry_id FROM [ROI_JournalDetailTemplate] where [ROI_FinancialTxnEvent_Seq] = -12 and ROI_FinancialEntityLineItemType_Seq = -43 end -- end if4 end -- end else1 END -- end if1 set @count = @count+1; end -- end while1 end
