Type_Seq] ,[ROI_LedgerAccount_Seq] ,[CreditDebitSideFlag] ,[DecreaseIncreaseFlag] ,@payment_id ,@Amount ,@Date ,@journalentry_id FROM [ROI_JournalDetailTemplate] where [ROI_FinancialTxnEvent_Seq] = -3
