justment_Seq],[Amount],[TxnOccurenceTimestamp],[ROI_JournalEntry_Seq]) SELECT [ROI_JournalDetailTemplate_Seq] ,[ROI_FinancialTxnEvent_Seq] ,[ROI_FinancialEntityLineItemType_Seq] ,[ROI_LedgerAccount_Seq] ,[CreditDebitSideFlag] ,[DecreaseIncreaseFlag] ,@invoiceToAdjustment_id ,@invoice_balance_due ,@Date ,@journalentry_id FROM [ROI_JournalDetailTemplate] where [ROI_FinancialTxnEvent_Seq] = -12 and ROI_FinancialEntityLineItemType_Seq = -42 insert into [ROI_JournalDetail] ([ROI_JournalDetailTemplate_Seq],[ROI_FinancialTxnEvent_Seq],[ROI_FinancialEntityLineItemType_Seq],[ROI_LedgerAccount_Seq],[CreditDebitSideFlag],[DecreaseIncreaseFlag],[ROI_RequestCoreDeliveryChargestoROI_RequestorAdjustment_Seq],[Amount],[TxnOccurenceTimestamp],[ROI_JournalEntry_Seq]) SELECT [ROI_JournalDetailTemplate_Seq] ,[ROI_FinancialTxnEvent_Seq] ,[ROI_FinancialEntityLineItemType_Seq] ,[ROI_LedgerAccount_Seq] ,[CreditDebitSideFlag] ,[DecreaseIncreaseFlag] ,@invoiceToAdjustment_id ,ISNULL(@apply_salesTax_amount,0.0) ,@Date ,@journalentry_id FROM [ROI_JournalDetailTemplate] where [ROI_FinancialTxnEvent_Seq] = -12 and ROI_FinancialEntityLineItemType_Seq = -43 end -- end if4 end -- end else1 END -- end if1 set @count = @count+1; while(@Remaining_Amount > 0) begin select @invoice_balance_due = Invoice_Balance_Due from ROI_RequestCoreDeliveryCharges where ROI_RequestCoreDeliveryCharges_Seq=@newinvoiceid; select @base_charge = Base_Charge from ROI_RequestCoreDeliveryCharges where ROI_RequestCoreDeliveryCharges_Seq=@newinvoiceid;
