insert into cabinet.dbo.ROI_ConversionMapping_RequestorAdjustment (ROI_RequestorAdjustment_Seq, ROI_RequestCore_Seq) select Transaction_Seq, @requestId from @tmpPaymentAdjustments1 where TransactionType='Adjustment' and IsDebit='False' and Transaction_Seq is not null;

insert into @tmpPrebill select rdc.ROI_RequestDeliveryCharges_Seq from cabinet.dbo.ROI_RequestDeliveryCharges rdc join ROI_RequestDelivery rd on rdc.ROI_RequestDelivery_Seq=rd.ROI_RequestDelivery_Seq where rdc.isInvoiced=1 and rd.ROI_RequestMain_Seq=@requestId and rdc.RequestDeliveryChargesXML.value('(/release-item[@type="billing-doc"]/attribute[@name="type"]/@value)[1]','varchar(max)') = 'PreBill'
if exists (select * from @tmpPrebill) begin insert into cabinet.dbo.ROI_RequestCoreDeliveryCharges (ROI_RequestCore_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, Previously_Released_Cost, Release_Date, Total_Pages, Total_Pages_Released, Salestax_Total_Amount, Salestax_Percentage_BillingLoc, Letter_Template_Name, Request_Status, Request_Date, LetterTemplate_FileId, Type, Invoice_Prebill_Date, Invoice_Due_Date, Resend_Date, Output_Method, Queue_Password, Invoice_Salestax, Base_Charge, Balance_Due, FACILITY_CODE, FACILITY_NAME, Invoice_Balance_Due, Is_Released, Billing_Type, Apply_SalesTax, Notes, Invoice_Due_Days, Overwrite_Due_Date, Unbillable, PreBill_Status, Unbillable_Amount) output inserted.ROI_RequestCoreDeliveryCharges_Seq, inserted.Created_By_Seq into @tmpNewPrebill select @requestId, irdc.Created_Dt, prebill.ROI_RequestDeliveryCharges_Seq, irdc.Modified_Dt, irdc.Modified_By_Seq, irdc.Record_Version, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="previously-released-cost"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Previously_Released_Cost, NULLIF(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="release-date"]/@value)[1]','smalldatetime'),'') as Release_Date, ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="total-pages"]/@value)[1]','int'),0) as Total_Pages, ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="total-pages-released"]/@value)[1]','int'),0) as Total_Pages_Released, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="salestax-total-amount"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Salestax_Total_Amount, ISNULL(p.value('(./attribute[@name="sales-tax-percentage"]/@value)[1]','decimal(18,2)'),0.00) as Salestax_Percentage_BillingLoc, p.value('(./attribute[@name="lettertemplate-name"]/@value)[1]','varchar(50)') as Letter_Template_Name, ISNULL(p.value('(./attribute[@name="request-status"]/@value)[1]','varchar(50)'),'') as Request_Status, p.value('(./attribute[@name="request-dt"]/@value)[1]','smalldatetime') as Request_Date, ISNULL(p.value('(./attribute[@name="lettertemplate-fileid"]/@value)[1]','int'),1) as LetterTemplate_FileId, ISNULL(p.value('(./attribute[@name="type"]/@value)[1]','varchar(10)'),'') as Type, ISNULL(p.value('(./attribute[@name="invoice-prebill-date"]/@value)[1]','smalldatetime'),p.value('(./attribute[@name="request-dt"]/@value)[1]','smalldatetime')) as Invoice_Prebill_Date, dateadd(day, @defaultInvoiceDueDays, irdc.Created_Dt) as Invoice_Due_Date, ISNULL(p.value('(./attribute[@name="resend-dt"]/@value)[1]','smalldatetime'),p.value('(./attribute[@name="request-dt"]/@value)[1]','smalldatetime')) as Resend_Date, ISNULL(p.value('(./attribute[@name="output-method"]/@value)[1]','varchar(50)'),'') as Output_Method, p.value('(./attribute[@name="queue-password"]/@value)[1]','varchar(50)') as Queue_Password, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="invoice-info"]/attribute[@name="inv-sales-tax"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Invoice_Salestax, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="release-cost"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Base_Charge, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="release-info"]/attribute[@name="balance-due"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Balance_Due, @defaultFacilityCode as FACILITY_CODE, @defaultFacilityName as FACILITY_NAME, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="invoice-info"]/attribute[@name="inv-balance-due"]/@value)[1]','varchar(20)'),0.00), '$',''), ')', ''), '(', '-'),',','') as Invoice_Balance_Due, irdc.isReleased, p.value('(release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="FeeCharge"]/attribute[@name="billing-type"]/@value)[1]','varchar(50)') as Billing_Type, 0 as Apply_SalesTax, (select stuff( (select '~'+ c.value('./@value[1]','varchar(max)') from [RequestDeliveryChargesXML].nodes('/release-item[@type="billing-doc"]/release-item[@type="notes"]/release-item/attribute[@name="description"]') as t(c) FOR XML PATH('')),1,1,'')) as Notes, @defaultInvoiceDueDays as Invoice_Due_Days, 0 as Overwrite_Due_Date, 0 as Unbillable, 'Active' as PreBill_Status, 0.00 as Unbillable_Amount from ROI_RequestDeliveryCharges irdc join @tmpPrebill prebill on irdc.ROI_RequestDeliveryCharges_Seq=prebill.ROI_RequestDeliveryCharges_Seq cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-doc"]') as p(p);
insert into cabinet.dbo.ROI_RequestCoreDeliveryChargesDocument (ROI_RequestCoreDeliveryCharges_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, Amount, Copies, TotalPages, Pages, BillingTierName, BillingTierId, ReleaseCount, isElectronic, RemoveBasecharge, Has_Salestax, Salestax_Amount) select (select ROI_RequestCoreDeliveryCharges_Seq from @tmpNewPrebill where ROI_RequestDeliveryCharges_Seq = prebill.ROI_RequestDeliveryCharges_Seq), drdc.Created_Dt, drdc.Created_By_Seq, drdc.Modified_Dt, drdc.Modified_By_Seq, drdc.Record_Version, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="amount"]/@value)[1]','varchar(20)'), 0.00), '$',''),')',''), '(', '-'),',','') as Amount, ISNULL(p.value('(./attribute[@name="copies"]/@value)[1]','varchar(20)'),0) as Copies, ISNULL(p.value('(./attribute[@name="total-pages"]/@value)[1]','varchar(20)'),0) as TotalPages, ISNULL(p.value('(./attribute[@name="pages"]/@value)[1]','varchar(20)'),0) as Pages, ISNULL(p.value('(./attribute[@name="billingtier-name"]/@value)[1]','varchar(256)'),'') as BillingTierName, ISNULL(p.value('(./attribute[@name="billingtier-id"]/@value)[1]','varchar(20)'),0) as BillingTierId, ISNULL(p.value('(./attribute[@name="release-count"]/@value)[1]','varchar(20)'),0) as ReleaseCount, case p.value('(./attribute[@name="is-electronic"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as IsElectronic, case p.value('(./attribute[@name="remove-basecharge"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as RemoveBaseCharge, case p.value('(./attribute[@name="has-salestax"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as Has_Salestax, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="salestax-amount"]/@value)[1]','varchar(max)'),0.00), '$',''), ')', ''), '(', '-'),',','') as SalesTax_Amount from ROI_RequestDeliveryCharges drdc join @tmpPrebill prebill on drdc.ROI_RequestDeliveryCharges_Seq=prebill.ROI_RequestDeliveryCharges_Seq cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-doc"]/release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="DocumentCharge"]/release-item') as p(p);
insert into cabinet.dbo.ROI_RequestCoreDeliveryChargesFee (ROI_RequestCoreDeliveryCharges_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, Amount, IsCustomFee, FeeType, Has_Salestax, Salestax_Amount) select (select ROI_RequestCoreDeliveryCharges_Seq from @tmpNewPrebill where ROI_RequestDeliveryCharges_Seq = prebill.ROI_RequestDeliveryCharges_Seq), drdc.Created_Dt, drdc.Created_By_Seq, drdc.Modified_Dt, drdc.Modified_By_Seq, drdc.Record_Version, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="amount"]/@value)[1]','varchar(max)'), 0.00), '$',''),')',''), '(', '-'),',','') as Amount, case p.value('(./attribute[@name="is-custom-fee"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as IsCustomFee, p.value('(./attribute[@name="feetype"]/@value)[1]','varchar(50)') as FeeType, case p.value('(./attribute[@name="has-salestax"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as Has_Salestax, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(./attribute[@name="salestax-amount"]/@value)[1]','varchar(max)'),0.00), '$',''), ')', ''), '(', '-'),',','') as SalesTax_Amount from ROI_RequestDeliveryCharges drdc join @tmpPrebill prebill on drdc.ROI_RequestDeliveryCharges_Seq=prebill.ROI_RequestDeliveryCharges_Seq cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-doc"]/release-item[@type="billing-info"]/release-item[@type="charges"]/release-item[@type="FeeCharge"]/release-item') as p(p);
insert into cabinet.dbo.ROI_RequestCoreDeliveryChargesShipping (ROI_RequestCoreDeliveryCharges_Seq, Created_Dt, Created_By_Seq, Modified_Dt, Modified_By_Seq, Record_Version, ShippingCharge, AddressType, Address1, Address2, Address3, City, State, PostalCode, ShippingUrl, ShippingWeight, TrackingNumber, WillReleaseShipped, ShippingMethod, OutputMethod, ShippingMethodId) select (select ROI_RequestCoreDeliveryCharges_Seq from @tmpNewPrebill where ROI_RequestDeliveryCharges_Seq = prebill.ROI_RequestDeliveryCharges_Seq), drdc.Created_Dt, drdc.Created_By_Seq, drdc.Modified_Dt, drdc.Modified_By_Seq, drdc.Record_Version, REPLACE(REPLACE(REPLACE(REPLACE(ISNULL(p.value('(../release-item[@type="charges"]/release-item[@type="shipping-charge"]/attribute[@name="shipping-charge"]/@value)[1]','varchar(max)'),0.00), '$',''), ')', ''), '(', '-'),',','') as ShippingCharge, p.value('(./attribute[@name="address-type"]/@value)[1]','varchar(20)') as AddressType, p.value('(./attribute[@name="address1"]/@value)[1]','varchar(256)') as Address1, p.value('(./attribute[@name="address2"]/@value)[1]','varchar(256)') as Address2, p.value('(./attribute[@name="address3"]/@value)[1]','varchar(256)') as Address3, p.value('(./attribute[@name="city"]/@value)[1]','varchar(50)') as City, p.value('(./attribute[@name="state"]/@value)[1]','varchar(20)') as State, p.value('(./attribute[@name="postalcode"]/@value)[1]','varchar(20)') as PostalCode, p.value('(./attribute[@name="shipping-url"]/@value)[1]','varchar(50)') as ShippingUrl, ISNULL(p.value('(./attribute[@name="shipping-weight"]/@value)[1]','varchar(max)'),0) as ShippingWeight, p.value('(./attribute[@name="tracking-number"]/@value)[1]','varchar(35)') as TrackingNumber, case p.value('(./attribute[@name="will-release-shipped"]/@value)[1]','varchar(1)') when 'T' then 1 else 0 end as WillReleaseShipped, p.value('(./attribute[@name="shipping-method"]/@value)[1]','varchar(35)') as ShippingMethod, p.value('(./attribute[@name="output-method"]/@value)[1]','varchar(35)') as OutputMethod, p.value('(./attribute[@name="shipping-method-id"]/@value)[1]','bigint') as ShippingMethodId from ROI_RequestDeliveryCharges drdc join @tmpPrebill prebill on drdc.ROI_RequestDeliveryCharges_Seq=prebill.ROI_RequestDeliveryCharges_Seq cross apply RequestDeliveryChargesXML.nodes('/release-item[@type="billing-doc"]/release-item[@type="billing-info"]/release-item[@type="shipping-info"]') as p(p);
end

insert into @tmpRequestCoreDelivery select [ROI_RequestDelivery_Seq], t.c.value('(./@queue-password)[1]','varchar(50)') as queuePwd, Created_Dt as Created_Dt, ROW_NUMBER() OVER(ORDER BY ROI_RequestDelivery_Seq) AS Created_By_Seq, Modified_Dt as Modified_Dt, Modified_By_Seq as Modified_By_Seq from ROI_RequestDelivery cross apply [RequestDeliveryXML].nodes('/release[@is-released="True" or @is-released="true"]') t(c) where [ROI_RequestMain_Seq] = @requestId;
if exists(select 1 from @tmpRequestCoreDelivery) BEGIN INSERT INTO ROI_RequestCoreDelivery ([ROI_RequestCore_Seq], Queue_Password, Created_Dt, Modified_Dt, Created_By_Seq, Modified_By_Seq) OUTPUT inserted.[ROI_RequestCoreDelivery_Seq], inserted.Created_By_Seq, inserted.ROI_RequestCore_Seq INTO @ROI_RequestCoreDelivery_IDX([ROI_RequestCoreDelivery_Seq], row_seq, ROI_RequestCore_Seq) select @requestId, queuePwd, Created_Dt, Modified_Dt, Created_By_Seq, Modified_By_Seq from @tmpRequestCoreDelivery
update a set [ROI_RequestDelivery_Seq] = tmp.[ROI_RequestDelivery_Seq] from @ROI_RequestCoreDelivery_IDX a join @tmpRequestCoreDelivery tmp ON a.row_seq = tmp.Created_By_Seq
--if(@isWheaton <> 'true') --BEGIN ---- is not wheaton --if exists(select 1 from @ROI_RequestCoreDeliveryCharges_IDX) --BEGIN --INSERT INTO ROI_RequestCoreDeliverytoROI_RequestCoreDeliveryCharges( ROI_RequestCoreDelivery_Seq, ROI_RequestCoreDeliveryCharges_Seq) --select [ROI_RequestCoreDelivery_Seq], -- (select [ROI_RequestCoreDeliveryCharges_seq] from @ROI_RequestCoreDeliveryCharges_IDX) --from @ROI_RequestCoreDelivery_IDX; --END --END --ELSE --BEGIN ---- is wheaton --INSERT INTO ROI_RequestCoreDeliverytoROI_RequestCoreDeliveryCharges( ROI_RequestCoreDelivery_Seq, ROI_RequestCoreDeliveryCharges_Seq) --select -- (select [ROI_RequestCoreDelivery_Seq] from @ROI_RequestCoreDelivery_IDX b where a.[ROI_RequestDelivery_Seq] = b.[ROI_RequestDelivery_Seq]), -- (select [ROI_RequestCoreDeliveryCharges_seq] from @ROI_RequestCoreDeliveryCharges_IDX c where a.[ROI_RequestDeliveryCharges_seq] = c.[ROI_RequestDeliveryCharges_seq]) --from ROI_RequestDeliveryCharges a --where [ROI_RequestDeliveryCharges_seq] in ( select [ROI_RequestDeliveryCharges_seq] from @ROI_RequestCoreDeliveryCharges_IDX) --and isReleased=1 --END
INSERT INTO ROI_RequestCoreDeliverytoROI_RequestCoreDeliveryCharges( ROI_RequestCoreDelivery_Seq, ROI_RequestCoreDeliveryCharges_Seq) select rcd.ROI_RequestCoreDelivery_Seq, rcdc.ROI_RequestCoreDeliveryCharges_Seq from @ROI_RequestCoreDelivery_IDX rcd join @ROI_RequestCoreDeliveryCharges_IDX rcdc on rcd.ROI_RequestCore_Seq = rcdc.ROI_RequestCore_Seq
insert into @tmpRequestCoreDeliveryPage select ROI_RequestDelivery_seq as ROI_RequestDelivery_seq, NULLIF(t.c.value('@number','varchar(max)'), '') as [page], NULLIF(t.c.value('@imnet-id','varchar(max)'), '') as [imnet] from ROI_RequestDelivery cross apply [RequestDeliveryXML].nodes('/release/item[@source="hpf"]/patient/global-document/version/page') t(c) where [ROI_RequestDelivery_seq] in (Select [ROI_RequestDelivery_seq] from @ROI_RequestCoreDelivery_IDX) Union select ROI_RequestDelivery_seq as ROI_RequestDelivery_seq, NULLIF(t1.c.value('@number','varchar(max)'), '') as [page], NULLIF(t1.c.value('@imnet-id','varchar(max)'), '') as [imnet] from ROI_RequestDelivery cross apply [RequestDeliveryXML].nodes('/release/item[@source="hpf"]/patient/encounter/document/version/page') t1(c) where [ROI_RequestDelivery_seq] in (Select [ROI_RequestDelivery_seq] from @ROI_RequestCoreDelivery_IDX); -- CR 387959/CR 388558 - Start set @pagesCount = (select min([ROI_Pages_Seq]) from @ROI_PAGES_IDX c,@tmpRequestCoreDeliveryPage a where a.[IMNET] = c.[IMNET] AND a.[page] = c.[page]) set @delSeqValue = (select min([ROI_RequestCoreDelivery_Seq]) from @tmpRequestCoreDeliveryPage a,@ROI_RequestCoreDelivery_IDX b where a.[ROI_RequestDelivery_Seq] = b.[ROI_RequestDelivery_Seq])
while @pagesCount is not null begin insert into ROI_RequestCoreDeliverytoROI_Pages ( ROI_RequestCoreDelivery_seq ,[ROI_Pages_Seq]) select @delSeqValue as ROI_RequestCoreDelivery_seq, @pagesCount as ROI_Pages_Seq set @pagesCount = (select MIN([ROI_Pages_Seq]) from @ROI_PAGES_IDX c,@tmpRequestCoreDeliveryPage a where a.[IMNET] = c.[IMNET] AND a.[page] = c.[page] and [ROI_Pages_Seq] > @pagesCount) end -- CR 387959/CR 388558 - End
-- DE10558 INSERT INTO @tmpRequestCoreDeliverySupplementarityDocuments SELECT *, ROW_NUMBER() OVER(PARTITION BY [DOCUMENTID] ORDER BY [DOCUMENTID]) as ROW_NUMBER FROM ( SELECT ROI_RequestDelivery_seq as ROI_RequestDelivery_seq, NULLIF(t.c.value('@id','varchar(max)'), '') as [DOCUMENTID], NULLIF(t.c.value('../../@mrn','varchar(max)'), '') as [MRN], NULLIF(t.c.value('../../@facility','varchar(max)'), '') as [FACILITY] from ROI_RequestDelivery cross apply [RequestDeliveryXML].nodes('/release/item[@source="hpf"]/patient/supplemental-encounter/document') t(c) ) as X where [ROI_RequestDelivery_seq] in (Select [ROI_RequestDelivery_seq] from @ROI_RequestCoreDelivery_IDX);
DECLARE @tmpROI_ConversionMapping_SupplementarityDocuments table ( [mrn] [varchar](20) NOT NULL, [facility] [varchar](10) NOT NULL, [document_id] [bigint] NOT NULL, [ROI_RequestCore_Seq] [bigint] NULL, [ROI_SupplementarityDocuments_Seq] [bigint] NOT NULL, [ROI_SupplementarityDocumentsCore_Seq] [bigint] NOT NULL, ROW_NUMBER int NOT NULL );
INSERT into @tmpROI_ConversionMapping_SupplementarityDocuments SELECT [mrn],[facility],[document_id],[ROI_RequestCore_Seq],[ROI_SupplementarityDocuments_Seq],[ROI_SupplementarityDocumentsCore_Seq], ROW_NUMBER() OVER(PARTITION BY [document_id] ORDER BY [ROI_SupplementarityDocumentsCore_Seq]) as ROW_NUMBER FROM ROI_ConversionMapping_SupplementarityDocuments WHERE ROI_RequestCore_Seq = @requestId
INSERT into ROI_RequestCoreDeliverytoROI_SupplementarityDocumentsCore ( ROI_RequestCoreDelivery_seq ,ROI_SupplementarityDocumentsCore_Seq) SELECT * from (SELECT (SELECT [ROI_RequestCoreDelivery_Seq] from @ROI_RequestCoreDelivery_IDX b where a.[ROI_RequestDelivery_Seq] = b.[ROI_RequestDelivery_Seq]) as ROI_RequestCoreDelivery_Seq, (SELECT [ROI_SupplementarityDocumentsCore_Seq] from @tmpROI_ConversionMapping_SupplementarityDocuments c where a.[MRN] = c.[MRN] AND a.[FACILITY] = c.[FACILITY] AND a.[DOCUMENTID] = c.[document_id] AND c.ROI_RequestCore_Seq = @requestId AND a.ROW_NUMBER = c.ROW_NUMBER ) as ROI_SupplementarityDocumentsCore_Seq FROM @tmpRequestCoreDeliverySupplementarityDocuments a) d WHERE d.ROI_SupplementarityDocumentsCore_Seq is not null; -- END DE10558
insert into @tmpRequestCoreDeliverySupplementarityAttachments select ROI_RequestDelivery_seq as ROI_RequestDelivery_seq, NULLIF(t.c.value('@id,','varchar(max)'), '') as [ATTACHMENTID], NULLIF(t.c.value('../../@mrn','varchar(max)'), '') as [MRN], NULLIF(t.c.value('../../@facility','varchar(max)'), '') as [FACILITY] from ROI_RequestDelivery cross apply [RequestDeliveryXML].nodes('/release/item[@source="hpf"]/patient/attachment-encounter/attachment') t(c) where [ROI_RequestDelivery_seq] in (Select [ROI_RequestDelivery_seq] from @ROI_RequestCoreDelivery_IDX);
insert into ROI_RequestCoreDeliverytoROI_SupplementarityAttachmentsCore ( ROI_RequestCoreDelivery_seq, ROI_SupplementarityAttachmentsCore_Seq) select * from (select (select [ROI_RequestCoreDelivery_Seq] from @ROI_RequestCoreDelivery_IDX b where a.[ROI_RequestDelivery_Seq] = b.[ROI_RequestDelivery_Seq]) as ROI_RequestCoreDelivery_Seq, (select [ROI_SupplementarityAttachmentsCore_Seq] from ROI_ConversionMapping_SupplementarityAttachments c where a.[MRN] = c.[MRN] AND a.[FACILITY] = c.[FACILITY] AND a.[ATTACHMENTID] = c.[attachment_id] AND c.ROI_RequestCore_Seq = @requestId ) as ROI_SupplementarityAttachmentsCore_Seq from @tmpRequestCoreDeliverySupplementarityAttachments a) d where d.ROI_SupplementarityAttachmentsCore_Seq is not null
insert into @tmpRequestCoreDeliverySupplementalDocuments select ROI_RequestDelivery_seq as ROI_RequestDelivery_seq, NULLIF(t.c.value('../../@id','varchar(max)'), '') as [PATIENTID], NULLIF(t.c.value('@id','varchar(max)'), '') as [DOCUMENTID] from ROI_RequestDelivery cross apply [RequestDeliveryXML].nodes('/release/item[@source="roi"]/patient/supplemental-encounter/document') t(c) where [ROI_RequestDelivery_seq] in (Select [ROI_RequestDelivery_seq] from @ROI_RequestCoreDelivery_IDX);
insert into ROI_RequestCoreDeliverytoROI_SupplementalDocumentsCore ( ROI_RequestCoreDelivery_seq, ROI_SupplementalDocumentsCore_Seq) select (select [ROI_RequestCoreDelivery_Seq] from @ROI_RequestCoreDelivery_IDX b where a.[ROI_RequestDelivery_Seq] = b.[ROI_RequestDelivery_Seq]), (select [ROI_SupplementalDocumentsCore_Seq] from ROI_ConversionMapping_SupplementalDocuments c where a.[PATIENTID] = c.[patient_id] AND a.[DOCUMENTID] = c.[document_id] AND c.ROI_RequestCore_Seq = @requestId ) from @tmpRequestCoreDeliverySupplementalDocuments a
insert into @tmpRequestCoreDeliverySupplementalAttachments select ROI_RequestDelivery_seq as ROI_RequestDelivery_seq, NULLIF(t.c.value('../../@id','varchar(max)'), '') as [PATIENTID], NULLIF(t.c.value('@id,','varchar(max)'), '') as [ATTACHMENTID] from ROI_RequestDelivery cross apply [RequestDeliveryXML].nodes('/release/item[@source="roi"]/patient/attachment-encounter/attachment') t(c) where [ROI_RequestDelivery_seq] in (Select [ROI_RequestDelivery_seq] from @ROI_RequestCoreDelivery_IDX);
insert into ROI_RequestCoreDeliverytoROI_SupplementalAttachmentsCore (ROI_RequestCoreDelivery_seq, ROI_SupplementalAttachmentsCore_Seq) select (select [ROI_RequestCoreDelivery_Seq] from @ROI_RequestCoreDelivery_IDX b where a.[ROI_RequestDelivery_Seq] = b.[ROI_RequestDelivery_Seq]), (select [ROI_SupplementalAttachmentsCore_Seq] from ROI_ConversionMapping_SupplementalAttachments c where a.[PATIENTID] = c.[patient_id] AND a.[ATTACHMENTID] = c.[attachment_id] AND c.ROI_RequestCore_Seq = @requestId ) from @tmpRequestCoreDeliverySupplementalAttachments a END

        
			if exists (select * from ROI_ConversionStatus_RequestMain where ROI_RequestMain_Seq = :requestId)
			begin
				UPDATE ROI_ConversionStatus_RequestMain SET Status = :status, Number_Of_Retries = Number_Of_Retries+1, ErrorMessage = :errorMessage, Conversion_Dt = GETDATE() WHERE ROI_RequestMain_Seq = :requestId;
			end
			else
			begin
				INSERT INTO ROI_ConversionStatus_RequestMain(ROI_RequestMain_Seq, Status, Number_Of_Retries, ErrorMessage, Conversion_Dt) values (:requestId,:status,:numRetries,:errorMessage, GETDATE());
			end
